function flattenAnchors(data) {
  const points = {};
  (data.groups || []).forEach((group) => {
    (group.anchors || []).forEach((anchor) => {
      points[anchor.id] = { x: Number(anchor.x), y: Number(anchor.y), label: anchor.label || anchor.id };
    });
  });
  return points;
}

function ensureDefs() {
  let defs = svg.querySelector("defs");
  if (!defs) {
    defs = document.createElementNS(NS, "defs");
    svg.insertBefore(defs, svg.firstElementChild);
  }
  return defs;
}

// v2 腮红坐标合同（逆向 confirmed 的 head-motion-mixer-v1 修好版）。
//
// 翻车根因不是"裁切几何 vs 内容仿射"，而是【呼吸 headMotion 被手动分别糊到
// 裁切框和内容上、绕不同中心旋转】。mixer 没有呼吸，那套
//   wrapper(裁切, 无 transform) > transformGroup(blushPlaneTransform 看向滑动) > 单颗腮红(per-blush 偏移)
// 既不抖又跟随看向，是鹿鹿确认过的状态。v1 加呼吸时给裁切框加 transform=headMotion、
// 给内容加 blushPlaneTransform+headMotion，两边各绕自己中心转 → 每帧错位抖动。
//
// v2 修法：原样复刻 mixer 的 wrapper>transformGroup>blushes 结构，但把 wrapper
// 作为 head-layer 的子节点 → 呼吸 headMotion 由父层【只施加一次】，裁切(在 wrapper)
// 与内容(在 transformGroup)同源继承、绕同一中心动 → 不抖。看向滑动 blushPlaneTransform
// 仍在 transformGroup 内（在裁切内部滑动，不拖动裁切）→ 腮红跟随看向、被脸边裁。
function prepareBlushClip() {
  const blushes = svg.querySelector("#blushes");
  const headLayer = svg.querySelector("#head-layer");
  if (!blushes || !headLayer || svg.querySelector("#idle-look-blush-clip-wrapper")) return;

  const clip = document.createElementNS(NS, "clipPath");
  clip.setAttribute("id", "idle-look-blush-clip");
  clip.setAttribute("clipPathUnits", "userSpaceOnUse");
  const clipPath = document.createElementNS(NS, "path");
  clipPath.setAttribute("id", "idle-look-blush-clip-path");
  clip.appendChild(clipPath);
  ensureDefs().appendChild(clip);

  // wrapper：套裁切、自身不加 transform（呼吸由 head-layer 父层承载）。
  const wrapper = document.createElementNS(NS, "g");
  wrapper.setAttribute("id", "idle-look-blush-clip-wrapper");
  wrapper.setAttribute("data-layer", "idle-blush-clip-host");
  wrapper.setAttribute("clip-path", "url(#idle-look-blush-clip)");

  // transformGroup：吃看向滑动 blushPlaneTransform（在裁切内部移动腮红，不动裁切）。
  const transformGroup = document.createElementNS(NS, "g");
  transformGroup.setAttribute("id", "idle-look-blush-transform");
  transformGroup.appendChild(blushes);
  wrapper.appendChild(transformGroup);

  // wrapper 作为 head-layer 末尾子节点：与白脸同父 → 呼吸 headMotion 只在父层施加一次。
  headLayer.appendChild(wrapper);
}

function prepareHeadPoseLayer() {
  const rootGroup = svg.querySelector("#hamster-flat-master-v11") || svg;
  if (rootGroup.querySelector("#thinking-head-pose-layer")) return;
  const nodes = ["ears-layer", "head-tufts", "head-layer", "face-layer"]
    .map((id) => svg.querySelector(`#${id}`))
    .filter(Boolean);
  if (!nodes.length) return;

  const wrapper = document.createElementNS(NS, "g");
  wrapper.setAttribute("id", "thinking-head-pose-layer");
  wrapper.setAttribute("data-layer", "thinking-whole-head-pose");
  rootGroup.insertBefore(wrapper, nodes[0]);
  nodes.forEach((node) => wrapper.appendChild(node));
  baseTransform["thinking-head-pose-layer"] = "";
}

function bindControls() {
  document.querySelector("#frameButtons").addEventListener("click", (event) => {
    const button = event.target.closest("button[data-progress]");
    if (!button) return;
    state.loopPlaying = false;
    stopLoop();
    state.breathProgress = Number(button.dataset.progress);
    syncControls();
    render();
  });

  document.querySelector("#lookButtons").addEventListener("click", (event) => {
    const button = event.target.closest("button[data-yaw]");
    if (!button) return;
    state.yaw = Number(button.dataset.yaw);
    state.pitch = Number(button.dataset.pitch);
    state.mouseLook = false;
    syncControls();
    render();
  });

  stage.addEventListener("pointermove", (event) => {
    if (!state.mouseLook) return;
    const rect = stage.getBoundingClientRect();
    const cx = rect.left + rect.width / 2;
    const cy = rect.top + rect.height * .42;
    const xRatio = clamp((event.clientX - cx) / (rect.width * .28), -1, 1);
    const yRatio = clamp((event.clientY - cy) / (rect.height * .30), -1, 1);
    state.yaw = Number(fmt(xRatio * state.mouseYawMax));
    state.pitch = Number(fmt(yRatio * state.mousePitchMax));
    syncControls();
    render();
  });

  document.querySelector("#poseButtons").addEventListener("click", (event) => {
    const button = event.target.closest("button[data-pose]");
    if (!button) return;
    state.pose = button.dataset.pose;
    Object.assign(state, POSES[state.pose]);
    syncControls();
    render();
  });

  document.querySelector("#sideButtons").addEventListener("click", (event) => {
    const button = event.target.closest("button[data-side]");
    if (!button) return;
    state.side = button.dataset.side;
    syncButtons();
    render();
  });

  document.querySelector("#shadowModeButtons").addEventListener("click", (event) => {
    const button = event.target.closest("button[data-shadow-mode]");
    if (!button) return;
    state.shadowMode = button.dataset.shadowMode;
    syncButtons();
    render();
  });

  document.querySelector("#thoughtDotsPaletteButtons").addEventListener("click", (event) => {
    const button = event.target.closest("button[data-thought-palette]");
    if (!button) return;
    state.thoughtDotsPalette = button.dataset.thoughtPalette;
    syncButtons();
    render();
  });

  document.querySelector("#resetShoulderPoints").addEventListener("click", () => {
    state.shoulderPoints = cloneShoulderPoints();
    render();
  });

  sliders.forEach((key) => {
    const input = document.querySelector(`#${key}`);
    input.addEventListener("input", () => {
      state[key] = Number(input.value);
      if (key === "breathProgress") {
        state.loopPlaying = false;
        stopLoop();
      }
      if (!breathSliders.includes(key)) state.pose = "custom";
      syncButtons();
      syncOutputs();
      render();
    });
  });

  checks.forEach((key) => {
    const input = document.querySelector(`#${key}`);
    input.addEventListener("change", () => {
      state[key] = input.checked;
      if (key === "loopPlaying") {
        if (state.loopPlaying) startLoop();
        else stopLoop();
      }
      syncButtons();
      render();
    });
  });

  document.querySelector("#copyJson").addEventListener("click", async () => {
    const text = JSON.stringify(snapshot(), null, 2);
    jsonOut.textContent = text;
    try {
      await navigator.clipboard.writeText(text);
      statusEl.textContent = "当前参数已复制。";
    } catch {
      statusEl.textContent = "当前参数已显示，浏览器没有开放剪贴板权限。";
    }
  });

  syncControls();
}

function startLoop() {
  stopLoop();
  const durationMs = Math.max(0.1, state.loopDuration) * 1000;
  loopEpoch = performance.now() - clamp(state.breathProgress, 0, 100) / 100 * durationMs;
  animationFrame = window.setTimeout(tickLoop, 0);
}

function stopLoop() {
  if (animationFrame) window.clearTimeout(animationFrame);
  animationFrame = 0;
}

function tickLoop(now = performance.now()) {
  animationFrame = 0;
  const durationMs = Math.max(0.1, state.loopDuration) * 1000;
  const phase = ((now - loopEpoch) % durationMs + durationMs) % durationMs;
  state.breathProgress = Number(fmt(phase / durationMs * 100));
  updateProgressControl();
  syncButtons();
  render();
  if (state.loopPlaying) animationFrame = window.setTimeout(tickLoop, 1000 / 30);
}

function updateProgressControl() {
  const input = document.querySelector("#breathProgress");
  const output = document.querySelector("#breathProgressOut");
  if (input) input.value = state.breathProgress;
  if (output) output.textContent = fmt(state.breathProgress);
}

function syncControls() {
  sliders.forEach((key) => {
    document.querySelector(`#${key}`).value = state[key];
  });
  checks.forEach((key) => {
    document.querySelector(`#${key}`).checked = state[key];
  });
  syncButtons();
  syncOutputs();
}

function syncButtons() {
  document.querySelectorAll("#frameButtons button").forEach((button) => {
    button.classList.toggle("active", Number(button.dataset.progress) === state.breathProgress);
  });
  document.querySelectorAll("#lookButtons button").forEach((button) => {
    button.classList.toggle("active",
      Number(button.dataset.yaw) === state.yaw &&
      Number(button.dataset.pitch) === state.pitch &&
      !state.mouseLook
    );
  });
  document.querySelectorAll("#poseButtons button").forEach((button) => {
    button.classList.toggle("active", button.dataset.pose === state.pose);
  });
  document.querySelectorAll("#sideButtons button").forEach((button) => {
    button.classList.toggle("active", button.dataset.side === state.side);
  });
  document.querySelectorAll("#shadowModeButtons button").forEach((button) => {
    button.classList.toggle("active", button.dataset.shadowMode === state.shadowMode);
  });
  document.querySelectorAll("#thoughtDotsPaletteButtons button").forEach((button) => {
    button.classList.toggle("active", button.dataset.thoughtPalette === state.thoughtDotsPalette);
  });
}

function syncOutputs() {
  sliders.forEach((key) => {
    document.querySelector(`#${key}Out`).textContent = fmt(state[key]);
  });
}

function rememberHandPaths() {
  for (const ids of Object.values(HAND_IDS)) {
    ids.forEach((id) => {
      const node = svg.querySelector(`#${id}`);
      if (node) baseD[id] = node.getAttribute("d") || "";
    });
  }
  const body = svg.querySelector("#body-belly-fill");
  if (body) baseD["body-belly-fill"] = body.getAttribute("d") || "";
  [
    "head-cap-fill", "cheek-muzzle-fill", "left-cheek-crease", "right-cheek-crease",
    "left-brow", "right-brow", "mouth-left", "mouth-right"
  ].forEach((id) => {
    const node = svg.querySelector(`#${id}`);
    if (node) baseD[id] = node.getAttribute("d") || "";
  });
  [
    "ears-layer", "head-layer", "head-tufts", "face-layer", "idle-look-blush-clip-wrapper", "idle-look-blush-transform", "tie",
    "tie-shadow", "tie-knot", "tie-blade", "tie-knot-highlight", "tie-center-fold", "tie-left-fold",
    "left-brow", "right-brow"
  ].forEach((id) => {
    const node = svg.querySelector(`#${id}`);
    if (node) baseTransform[id] = node.getAttribute("transform") || "";
  });
}

function render() {
  if (!svg) return;
  clearDiagnostics();

  const originalHands = svg.querySelector("#hands-layer");
  if (originalHands) {
    originalHands.style.display = state.showOriginal ? "" : "none";
    originalHands.setAttribute("opacity", state.showOriginal ? ".28" : "1");
  }

  applyBreathPose();
  applyDim();
  const bodyPath = svg.querySelector("#body-belly-fill");
  bodyPolygon = bodyPath ? samplePath(bodyPath, 190) : [];

  const rootGroup = svg.querySelector("#hamster-flat-master-v11") || svg;
  const bodyLayer = svg.querySelector("#body-layer");
  const headLayer = svg.querySelector("#thinking-head-pose-layer") || svg.querySelector("#ears-layer") || svg.querySelector("#head-layer") || null;
  const backLayer = el("g", { id: "arm-back-split-layer", "data-layer": "idle-complete-hands-behind-body" });
  const castShadowLayer = el("g", { id: "body-cast-shadow-on-hand-layer", "data-layer": "idle-body-shadow-on-hands" });
  const stickerArmLayer = el("g", {
    id: "thinking-sticker-arm-layer",
    "data-layer": "thinking-png-arm-sticker",
    "data-layer-mode": state.thinkingStickerTopPreview ? "temporary-top-preview" : "formal-under-head"
  });
  const stickerPawLayer = el("g", {
    id: "thinking-sticker-paw-layer",
    "data-layer": "thinking-png-paw-sticker",
    "data-layer-mode": state.thinkingStickerTopPreview ? "temporary-top-preview" : "formal-above-head"
  });
  const shoulderEditLayer = el("g", { id: "thinking-shoulder-edit-layer", "data-layer": "thinking-shoulder-manual-editor" });
  const thinkingHandLayer = el("g", { id: "thinking-front-hand-layer", "data-layer": "thinking-front-hand" });
  const thoughtDotsLayer = el("g", { id: "thinking-thought-dots-layer", "data-layer": "thinking-thought-dots" });
  const guideLayer = el("g", { id: "hand-layer-split-guide", "data-layer": "diagnostic-guides" });

  if (bodyLayer) {
    rootGroup.insertBefore(backLayer, bodyLayer);
    rootGroup.insertBefore(castShadowLayer, bodyLayer);
  } else {
    rootGroup.insertBefore(backLayer, rootGroup.firstChild);
    rootGroup.insertBefore(castShadowLayer, backLayer.nextSibling);
  }
  if (headLayer) {
    rootGroup.insertBefore(guideLayer, headLayer);
  } else {
    rootGroup.append(guideLayer);
  }

  if (state.thinkingStickerTopPreview) {
    rootGroup.appendChild(stickerArmLayer);
    rootGroup.appendChild(stickerPawLayer);
  } else if (bodyLayer) {
    rootGroup.insertBefore(stickerArmLayer, bodyLayer.nextSibling);
    rootGroup.appendChild(stickerPawLayer);
  } else {
    rootGroup.appendChild(stickerArmLayer);
    rootGroup.appendChild(stickerPawLayer);
  }

  if (state.thinkingHandTopPreview) {
    rootGroup.appendChild(thinkingHandLayer);
  } else if (bodyLayer) {
    rootGroup.insertBefore(thinkingHandLayer, bodyLayer.nextSibling);
  } else {
    rootGroup.appendChild(thinkingHandLayer);
  }
  rootGroup.appendChild(thoughtDotsLayer);
  rootGroup.appendChild(shoulderEditLayer);

  markers = {};
  for (const side of ["left", "right"]) {
    if (!sideActive(side)) continue;
    const data = buildSideData(side);
    markers[side] = data;
    if (state.showBackGuide) drawBackHandReference(backLayer, side, data);
    drawCompleteHand(backLayer, side, data);
    drawBodyCastShadowOnHand(castShadowLayer, side, data);
    if (state.showGuides) drawGuides(guideLayer, side, data);
  }
  drawThinkingSticker(stickerArmLayer, stickerPawLayer, shoulderEditLayer);
  drawThinkingFrontHand(thinkingHandLayer);
  drawThoughtDots(thoughtDotsLayer);
  if (statusEl) statusEl.textContent = `${state.loopPlaying ? "播放中" : "定帧"} ${fmt(state.breathProgress)}%；${lookStatus()}；眉毛 ${fmt(clamp(state.browExpression, 0, 2))} / 微弧 ${fmt(effectiveBrowMicro().level)}；嘴巴收口 ${state.mouthMaskVisible ? fmt(effectiveMouthMaskInset()) : "关"}；贴片绑定 小臂${fmt(state.stickerArmExhaleDrop)} / 爪尖${fmt(state.stickerPawExhaleDrop)}`;
  const now = performance.now();
  if (jsonOut && (!state.loopPlaying || now - lastJsonUpdate > 250)) {
    jsonOut.textContent = JSON.stringify(snapshot(), null, 2);
    lastJsonUpdate = now;
  }
}

function applyBreathPose() {
  const b = breathAmount(THINKING_BREATH_CURVES.body);
  const body = svg.querySelector("#body-belly-fill");
  if (body) body.setAttribute("d", Math.abs(b) < 1e-6 ? (baseD["body-belly-fill"] || bodyBreathPath(0)) : bodyBreathPath(b));
  setLayerTransform("thinking-head-pose-layer", headPoseTransform());
  applyHeadBreathMotion();
  setLayerTransform("tie", "");
  applyTieBreathMotion(breathAmount(THINKING_BREATH_CURVES.tie));
}

function applyHeadBreathMotion() {
  const headB = breathAmount(THINKING_BREATH_CURVES.head);
  const faceB = breathAmount(THINKING_BREATH_CURVES.face);
  const earB = breathAmount(THINKING_BREATH_CURVES.ear);
  const tuftB = breathAmount(THINKING_BREATH_CURVES.tuft);
  const headY = -state.headFloat * headB;
  const nod = state.headNod * headB;
  const faceLagY = state.faceLag * faceB;
  const earLagY = state.earLag * earB;
  const tuftY = headY - state.tuftFloat * tuftB;
  const headMotion = composeBreathTransforms(
    translateY(headY),
    rotateAroundHead(nod)
  );
  const faceMotion = composeBreathTransforms(
    translateY(headY + faceLagY),
    rotateAroundHead(nod * .82),
    scaleAroundFace(1 + state.faceBreathScale / 100 * faceB)
  );
  const earMotion = composeBreathTransforms(
    translateY(headY + earLagY),
    rotateAroundHead(nod * .35)
  );
  const tuftBreathMotion = composeBreathTransforms(
    translateY(tuftY),
    rotateAroundTuft(nod * -.9)
  );
  const lookActive = headLookActive();
  const cheek = cheekPath();
  const elem = elementOffsets();
  const ears = earState();

  setAttr("head-cap-fill", "d", headCapPath());
  setAttr("cheek-muzzle-fill", "d", cheek);
  // v2: 裁切框只设 d（=白脸同一帧 cheek，local 坐标），【绝不加 transform】；
  // 呼吸 headMotion 由 head-layer 父层统一承载（wrapper 是 head-layer 子节点）。
  setAttr("idle-look-blush-clip-path", "d", cheek);
  setAttr("left-cheek-crease", "d", creasePath("left"));
  setAttr("right-cheek-crease", "d", creasePath("right"));
  setAttr("left-cheek-crease", "stroke-width", lookActive ? "2.6" : "3");
  setAttr("right-cheek-crease", "stroke-width", lookActive ? "2.6" : "3");

  setLayerTransform("head-layer", headMotion);
  setLayerTransform("face-layer", composeBreathTransforms(lookActive ? facePlaneTransform(true) : "", faceMotion));
  // v2: wrapper 在 head-layer 内、继承呼吸 headMotion，自身【保持无 transform】；
  // 看向滑动 blushPlaneTransform 只放 transformGroup（在裁切内部滑、不拖动裁切）→ 跟随看向且不抖。
  setLayerTransform("idle-look-blush-clip-wrapper", "");
  setElementTransform("idle-look-blush-transform", lookActive ? blushPlaneTransform() : "");
  setLayerTransform("ears-layer", earMotion);
  setLayerTransform("head-tufts", composeBreathTransforms(lookActive ? tuftLookTransform() : "", tuftBreathMotion));

  setAttr("left-ear", "transform", lookActive ? translate(ears.left.x, ears.left.y) : "");
  setAttr("right-ear", "transform", lookActive ? translate(ears.right.x, ears.right.y) : "");
  setAttr("left-ear-outer", "r", fmt(lerp(34, 37.4, ears.left.grow)));
  setAttr("left-ear-inner", "r", fmt(lerp(18, 19.8, ears.left.grow)));
  setAttr("right-ear-outer", "r", fmt(lerp(34, 37.4, ears.right.grow)));
  setAttr("right-ear-inner", "r", fmt(lerp(18, 19.8, ears.right.grow)));

  const blink = blinkAmount();
  setAttr("left-eye", "rx", "12.5");
  setAttr("right-eye", "rx", "12.5");
  setAttr("left-eye", "ry", fmt(lerp(17, 4.2, blink)));
  setAttr("right-eye", "ry", fmt(lerp(17, 4.2, blink)));
  setAttr("left-eye", "transform", centeredTransform({ x: 138, y: 157 }, elem.leftEye.dx, elem.leftEye.dy));
  setAttr("right-eye", "transform", centeredTransform({ x: 237, y: 157 }, elem.rightEye.dx, elem.rightEye.dy));
  // v2: 恢复 mixer 的每颗腮红看向偏移（在 transformGroup 的 blushPlaneTransform 之内再微调）。
  setAttr("left-blush", "transform", centeredTransform({ x: 92, y: 185 }, elem.leftBlush.dx, elem.leftBlush.dy, elem.leftBlush.sx, elem.leftBlush.sy));
  setAttr("right-blush", "transform", centeredTransform({ x: 281, y: 185 }, elem.rightBlush.dx, elem.rightBlush.dy, elem.rightBlush.sx, elem.rightBlush.sy));
  setAttr("nose-mouth", "transform", "");
  applyBrowExpressionMotion();
  applyMouthMaskMotion();
}

function translateY(y) {
  return Math.abs(y) < 1e-6 ? "" : `translate(0 ${fmt(y)})`;
}

function translate(x, y) {
  return Math.abs(x) < 1e-6 && Math.abs(y) < 1e-6 ? "" : `translate(${fmt(x)} ${fmt(y)})`;
}

function rotateAroundHead(angle) {
  return Math.abs(angle) < 1e-6 ? "" : `rotate(${fmt(angle)} 187 205)`;
}

function rotateAroundPoint(angle, x, y) {
  return Math.abs(angle) < 1e-6 ? "" : `rotate(${fmt(angle)} ${fmt(x)} ${fmt(y)})`;
}

function scaleAroundHead(scaleValue) {
  return Math.abs(scaleValue - 1) < 1e-6 ? "" : `translate(187 205) scale(${fmt(scaleValue)}) translate(-187 -205)`;
}

function scaleAroundFace(scaleValue) {
  return Math.abs(scaleValue - 1) < 1e-6 ? "" : `translate(187 176) scale(${fmt(scaleValue)}) translate(-187 -176)`;
}

function headPoseTransform() {
  const sway = thinkingHeadSway();
  return composeBreathTransforms(
    translate(state.headPoseX, state.headPoseY),
    translate(sway.x, sway.y),
    rotateAroundHead(state.headPoseRotate),
    rotateAroundHead(thinkingHeadWobble()),
    scaleAroundHead(state.headPoseScale)
  );
}

function loopCycleProgress(cycleSeconds) {
  const base = clamp(state.breathProgress, 0, 100) / 100;
  const loopSeconds = Math.max(0.1, state.loopDuration);
  const seconds = Math.max(0.3, cycleSeconds || loopSeconds);
  return ((base * loopSeconds / seconds) % 1 + 1) % 1;
}

function expressionProgress() {
  return loopCycleProgress(state.expressionCycle);
}

function thinkingHeadWobble() {
  if (state.headThinkWobble <= 0) return 0;
  const t = expressionProgress();
  return state.headThinkWobble * Math.sin(Math.PI * 2 * t);
}

function thinkingHeadSway() {
  if (state.headThinkSway <= 0) return { x: 0, y: 0 };
  const t = expressionProgress();
  const swing = Math.sin(Math.PI * 2 * t);
  const lift = (1 - Math.cos(Math.PI * 2 * t)) / 2;
  return {
    x: state.headThinkSway * swing,
    y: -state.headThinkSway * .18 * lift
  };
}

function browPathFromPoints(points) {
  return `M${fmt(points.start.x)} ${fmt(points.start.y)} C${fmt(points.c1.x)} ${fmt(points.c1.y)} ${fmt(points.c2.x)} ${fmt(points.c2.y)} ${fmt(points.end.x)} ${fmt(points.end.y)}`;
}

function applyBrowExpressionMotion() {
  const amount = clamp(state.browExpression, 0, 2);
  if (amount <= 0) {
    setElementTransform("left-brow", "");
    setElementTransform("right-brow", "");
    setAttr("left-brow", "d", baseD["left-brow"] || browPathFromPoints(BROW_BASE.left));
    setAttr("right-brow", "d", baseD["right-brow"] || browPathFromPoints(BROW_BASE.right));
    return;
  }
  const left = BROW_BASE.left;
  const right = BROW_BASE.right;
  const highLift = state.browHighLift * amount;
  const highArch = state.browHighArch * amount;
  const highShorten = state.browHighShorten * amount;
  const lowDrop = state.browLowDrop * amount;
  const lowInvert = state.browLowInvert * amount;
  const lowShorten = state.browLowShorten * amount;
  const micro = effectiveBrowMicro(amount);
  const leftPoints = {
    start: { x: left.start.x + highShorten, y: left.start.y - highLift + .25 * amount },
    c1: { x: left.c1.x + highShorten * .18, y: left.c1.y - highLift - highArch - micro.left * .9 },
    c2: { x: left.c2.x - highShorten * .18, y: left.c2.y - highLift - highArch * .62 - micro.left * .55 },
    end: { x: left.end.x - highShorten, y: left.end.y - highLift - .75 * amount }
  };
  const rightPoints = {
    start: { x: right.start.x - lowShorten, y: right.start.y + lowDrop - .25 * amount },
    c1: { x: right.c1.x - lowShorten * .12, y: right.c1.y + lowDrop + lowInvert + micro.right * .95 },
    c2: { x: right.c2.x + lowShorten * .18, y: right.c2.y + lowDrop + lowInvert * .86 + micro.right * .72 },
    end: { x: right.end.x + lowShorten, y: right.end.y + lowDrop + .35 * amount }
  };
  setElementTransform("left-brow", "");
  setElementTransform("right-brow", "");
  setAttr("left-brow", "d", browPathFromPoints(leftPoints));
  setAttr("right-brow", "d", browPathFromPoints(rightPoints));
  setAttr("left-brow", "data-brow-amount", fmt(amount));
  setAttr("right-brow", "data-brow-amount", fmt(amount));
  setAttr("left-brow", "data-brow-micro", fmt(micro.left));
  setAttr("right-brow", "data-brow-micro", fmt(micro.right));
}

function effectiveBrowMicro(amount = clamp(state.browExpression, 0, 2)) {
  const level = clamp(state.browMicroArc, 0, 2) * amount;
  if (level <= 0) return { level: 0, left: 0, right: 0 };
  const t = expressionProgress();
  const envelope = Math.sin(Math.PI * t) ** 2;
  const leftPulse = envelope * (.62 + .38 * Math.sin(Math.PI * 2 * t + Math.PI / 5));
  const rightPulse = envelope * (.68 + .32 * Math.sin(Math.PI * 2 * t - Math.PI / 4));
  return {
    level,
    left: level * leftPulse,
    right: level * rightPulse
  };
}

function applyMouthMaskMotion() {
  setAttr("mouth-left", "d", baseD["mouth-left"] || "M187 177 C187 190 180 198 171 198 C166 198 163 195 163 192");
  setAttr("mouth-right", "d", baseD["mouth-right"] || "M187 177 C187 190 194 198 203 198 C208 198 211 195 211 192");
  const inset = effectiveMouthMaskInset();
  setAttr("mouth-left", "data-mouth-mask-inset", fmt(inset));
  setAttr("mouth-right", "data-mouth-mask-inset", fmt(inset));
  ["mouth-left", "mouth-right"].forEach((id) => {
    const node = svg.querySelector(`#${id}`);
    if (!node || !node.getTotalLength) return;
    setAttr(id, "clip-path", "");
    if (inset <= 0) {
      setAttr(id, "stroke-dasharray", "");
      setAttr(id, "stroke-dashoffset", "");
      return;
    }
    const length = node.getTotalLength();
    const visibleLength = Math.max(0.1, length - inset);
    setAttr(id, "stroke-dasharray", `${fmt(visibleLength)} ${fmt(length + 24)}`);
    setAttr(id, "stroke-dashoffset", "0");
  });
}

function effectiveMouthMaskInset() {
  if (!state.mouthMaskVisible) return 0;
  if (!state.mouthMaskBreath) return clamp(state.mouthMaskInset, 0, 18);
  const mouthBreath = clamp(breathAmount(THINKING_BREATH_CURVES.face), 0, 1);
  return lerp(5, 10, mouthBreath);
}

function rotateAroundTuft(angle) {
  return Math.abs(angle) < 1e-6 ? "" : `rotate(${fmt(angle)} 198 48)`;
}

function composeBreathTransforms(...parts) {
  return parts.filter(Boolean).join(" ");
}

function blinkAmount() {
  if (!state.blinkEnabled || state.blinkStrength <= 0) return 0;
  const center = clamp(state.blinkCenter, 0, 100);
  const halfSpan = Math.max(0.4, state.blinkSpan / 2);
  const distance = cyclicDistance(clamp(state.breathProgress, 0, 100), center);
  if (distance >= halfSpan) return 0;
  return smooth01(1 - distance / halfSpan) * clamp(state.blinkStrength, 0, 1);
}

function cyclicDistance(a, b) {
  const d = Math.abs(a - b);
  return Math.min(d, 100 - d);
}

function setAttr(id, name, value) {
  const node = svg.querySelector(`#${id}`);
  if (!node) return;
  if (value === null || value === undefined || value === "") node.removeAttribute(name);
  else node.setAttribute(name, value);
}

function headLookActive() {
  return Math.abs(state.yaw) > .001 || Math.abs(state.pitch) > .001;
}

function axisT(value) {
  return smooth01(Math.abs(value) / 100);
}

function diagonalFactor() {
  return Math.abs(state.yaw) / 100 * Math.abs(state.pitch) / 100;
}

function trimmed(value, trimScale = 1) {
  const trim = 1 - diagonalFactor() * 15 / 100 * trimScale;
  return value * trim;
}

function smoothRange(start, end, value) {
  return smooth01(clamp((value - start) / (end - start), 0, 1));
}

function mixPoint(a, b, t) {
  return { x: lerp(a.x, b.x, t), y: lerp(a.y, b.y, t) };
}

function interpolateNumberString(from, to, t) {
  const a = numbers(from);
  const b = numbers(to);
  let index = 0;
  if (!from || !to || a.length !== b.length) return t < 1 ? from : to;
  return from.replace(/-?\d*\.?\d+(?:e[-+]?\d+)?/gi, () => fmt(lerp(a[index], b[index++] ?? a[index - 1], t)));
}

function transformTopPoint(point, dir) {
  const axisX = dir < 0 ? 125 : 249;
  const axisTravel = (axisX - VIEW_W / 2) * .75;
  const localX = point.x - axisX;
  const next = { x: axisTravel + axisX + localX, y: point.y };
  const a = rawAnchors.A || { x: 65 };
  const g = rawAnchors.G || { x: 309 };
  const weightT = clamp((point.x - a.x) / (g.x - a.x), 0, 1);
  const weight = Math.pow(Math.sin(Math.PI * weightT), .9);
  return {
    x: point.x + (next.x - point.x) * weight,
    y: point.y
  };
}

function catmullPath(points, tension = .72, sharpness = .34) {
  const segs = [`M${fmt(points[0].x)} ${fmt(points[0].y)}`];
  for (let i = 0; i < points.length - 1; i += 1) {
    const p0 = points[Math.max(0, i - 1)];
    const p1 = points[i];
    const p2 = points[i + 1];
    const p3 = points[Math.min(points.length - 1, i + 2)];
    const nearBridge = ["C", "D", "E"].includes(p1.id) || ["C", "D", "E"].includes(p2.id);
    const localTension = tension * (nearBridge ? (1 - sharpness * .42) : 1);
    const c1 = {
      x: p1.x + (p2.x - p0.x) * localTension / 6,
      y: p1.y + (p2.y - p0.y) * localTension / 6
    };
    const c2 = {
      x: p2.x - (p3.x - p1.x) * localTension / 6,
      y: p2.y - (p3.y - p1.y) * localTension / 6
    };
    segs.push(`C${fmt(c1.x)} ${fmt(c1.y)} ${fmt(c2.x)} ${fmt(c2.y)} ${fmt(p2.x)} ${fmt(p2.y)}`);
  }
  return segs.join(" ");
}

function yawFacePath() {
  const dir = Math.sign(state.yaw);
  const t = axisT(state.yaw);
  if (!dir || t <= .001 || TOP_CHAIN.some((id) => !rawAnchors[id])) return BASE.cheekD;
  const top = TOP_CHAIN.map((id) => {
    const start = rawAnchors[id];
    const end = transformTopPoint(start, dir);
    return { id, ...mixPoint(start, end, t) };
  });
  const sideTail = dir < 0 ? LEFT_TAIL : RIGHT_TAIL;
  const tail = FRONT_TAIL.map((seg, index) => {
    const mixed = seg.map((value, numberIndex) => lerp(value, sideTail[index][numberIndex], t));
    return `C${fmt(mixed[0])} ${fmt(mixed[1])} ${fmt(mixed[2])} ${fmt(mixed[3])} ${fmt(mixed[4])} ${fmt(mixed[5])}`;
  }).join(" ");
  return `${catmullPath(top)} ${tail}Z`;
}

function faceLowerEffect() {
  if (state.pitch <= 0) return 0;
  return axisT(state.pitch) * lerp(.45, 1, axisT(state.yaw));
}

function faceLowerWrappedPoint(point) {
  const effect = faceLowerEffect();
  if (effect <= .001) return point;
  const lower = smoothRange(238, 263, point.y);
  if (lower <= .001) return point;
  const side = Math.sign(point.x - 187);
  return {
    x: point.x + side * 6 * effect * lower * .3,
    y: point.y + 12 * effect * lower
  };
}

function faceLowerWrappedPath(path) {
  return transformPathPairs(path, faceLowerWrappedPoint);
}

function pitchDeltaY(y) {
  if (state.pitch === 0) return 0;
  const sign = Math.sign(state.pitch);
  const t = axisT(state.pitch);
  const lowerWeight = clamp((y - 166) / 92, 0, 1);
  if (sign < 0) return lerp(PITCH_UP.axis, PITCH_UP.lower, lowerWeight) * t;
  return lerp(PITCH_DOWN.axis, PITCH_DOWN.lower, lowerWeight) * t;
}

function warpPathForPitch(path) {
  let index = 0;
  return path.replace(/-?\d*\.?\d+(?:e[-+]?\d+)?/gi, (value) => {
    const n = Number(value);
    const next = index % 2 === 1 ? n + pitchDeltaY(n) : n;
    index += 1;
    return fmt(next);
  });
}

function cheekPath() {
  return faceLowerWrappedPath(warpPathForPitch(yawFacePath()));
}

function headCapPath() {
  const yawT = axisT(state.yaw);
  const dir = Math.sign(state.yaw);
  const yawTarget = dir > 0 ? RIGHT_HEAD_CAP_D : LEFT_HEAD_CAP_D;
  const yawPath = dir ? interpolateNumberString(BASE.headCapD, yawTarget, yawT) : BASE.headCapD;
  let index = 0;
  return yawPath.replace(/-?\d*\.?\d+(?:e[-+]?\d+)?/gi, (value) => {
    const n = Number(value);
    if (index % 2 === 0) {
      index += 1;
      return fmt(n);
    }
    const topWeight = clamp((120 - n) / 80, 0, 1);
    const sideWeight = clamp((n - 120) / 70, 0, 1);
    const sign = Math.sign(state.pitch);
    const t = axisT(state.pitch);
    const delta = sign < 0
      ? (2 * topWeight - 5.61 * sideWeight) * t
      : (-1.87 * topWeight + 7.28 * sideWeight) * t;
    index += 1;
    return fmt(n + delta);
  });
}

function creasePath(side) {
  const isLeft = side === "left";
  const base = BASE[isLeft ? "leftCreaseD" : "rightCreaseD"];
  const sideSign = isLeft ? 1 : -1;
  const startX = isLeft ? 62 : 312;
  const baseLength = 38;
  const yawT = axisT(state.yaw);
  const yawPull = Math.sign(state.yaw) * yawT;
  const pitchT = axisT(state.pitch);
  return transformPathPairs(base, (point) => {
    const along = isLeft
      ? clamp((point.x - 62) / baseLength, 0, 1)
      : clamp((312 - point.x) / baseLength, 0, 1);
    let next = {
      x: startX + (point.x - startX),
      y: point.y
    };
    next.x += yawPull * (isLeft ? 1 : -1) * lerp(3, 6, along);
    next.x += sideSign * lerp(1.8, 2.4, along) * pitchT;
    next.y += pitchDeltaY(point.y);
    return faceLowerWrappedPoint(next);
  });
}

function facePlaneTransform(withPitchScale) {
  const dir = Math.sign(state.yaw);
  const yawT = axisT(state.yaw);
  const axis = 187 + dir * 62 * yawT;
  const dx = dir * 46.5 * yawT;
  const pitchSign = Math.sign(state.pitch);
  const pitchT = axisT(state.pitch);
  const pitchData = pitchSign < 0 ? PITCH_UP : PITCH_DOWN;
  const dy = trimmed(pitchData.faceDy * pitchT, .45);
  const sy = withPitchScale ? lerp(1, pitchData.faceSy, pitchT) : 1;
  return `translate(${fmt(dx)} ${fmt(dy)}) translate(${fmt(axis)} 172) skewX(0) scale(1 ${fmt(sy)}) translate(${fmt(-axis)} -172)`;
}

function blushPlaneTransform() {
  const dir = Math.sign(state.yaw);
  const yawT = axisT(state.yaw);
  const axis = 187 + dir * 62 * yawT;
  const dx = dir * 46.5 * yawT;
  const pitchSign = Math.sign(state.pitch);
  const pitchT = axisT(state.pitch);
  const pitchData = pitchSign < 0 ? PITCH_UP : PITCH_DOWN;
  const dy = trimmed(pitchData.blushDy * pitchT, .35);
  return `translate(${fmt(dx)} ${fmt(dy)}) translate(${fmt(axis)} 172) skewX(0) scale(1 1) translate(${fmt(-axis)} -172)`;
}

function centeredTransform(origin, dx, dy, sx = 1, sy = 1) {
  if (Math.abs(dx) < 1e-6 && Math.abs(dy) < 1e-6 && Math.abs(sx - 1) < 1e-6 && Math.abs(sy - 1) < 1e-6) return "";
  return `translate(${fmt(origin.x + dx)} ${fmt(origin.y + dy)}) scale(${fmt(sx)} ${fmt(sy)}) translate(${fmt(-origin.x)} ${fmt(-origin.y)})`;
}

function elementOffsets() {
  const dir = Math.sign(state.yaw);
  const yawT = axisT(state.yaw);
  const pitchSign = Math.sign(state.pitch);
  const pitchT = axisT(state.pitch);
  const pitchUp = pitchSign < 0;
  const pitchEye = pitchUp ? -.56 * pitchT : 0;
  const pitchBlushDx = pitchUp ? 3.5 * pitchT : -1.8 * pitchT;
  const yawLeftEye = dir < 0 ? -2 * yawT : 0;
  const yawRightEye = dir > 0 ? 2 * yawT : 0;
  const leftBlushYaw = dir < 0
    ? { dx: 6.5 * yawT, dy: 0, sx: 1, sy: 1 }
    : { dx: -24 * yawT, dy: 20.5 * yawT, sx: lerp(1, 1.09, yawT), sy: lerp(1, 1.1, yawT) };
  const rightBlushYaw = dir < 0
    ? { dx: 25 * yawT, dy: 20.5 * yawT, sx: lerp(1, 1.09, yawT), sy: lerp(1, 1.1, yawT) }
    : { dx: -5.5 * yawT, dy: 0, sx: 1, sy: 1 };
  return {
    leftEye: { dx: yawLeftEye, dy: pitchEye },
    rightEye: { dx: yawRightEye, dy: pitchEye },
    leftBlush: {
      dx: leftBlushYaw.dx + pitchBlushDx,
      dy: leftBlushYaw.dy,
      sx: leftBlushYaw.sx,
      sy: leftBlushYaw.sy
    },
    rightBlush: {
      dx: rightBlushYaw.dx - pitchBlushDx,
      dy: rightBlushYaw.dy,
      sx: rightBlushYaw.sx,
      sy: rightBlushYaw.sy
    }
  };
}

function earState() {
  const dir = Math.sign(state.yaw);
  const yawT = axisT(state.yaw);
  const pitchSign = Math.sign(state.pitch);
  const pitchT = axisT(state.pitch);
  const pitchData = pitchSign < 0 ? PITCH_UP : PITCH_DOWN;
  const pitchDy = pitchData.earDy * pitchT;
  const left = { x: 0, y: pitchDy, grow: 0 };
  const right = { x: 0, y: pitchDy, grow: 0 };
  if (dir < 0) {
    left.x += -3.5 * yawT;
    left.y += 3.5 * yawT;
    right.grow = smoothRange(.12, 1, yawT);
  } else if (dir > 0) {
    right.x += -9.5 * yawT;
    right.y += 3.5 * yawT;
    left.grow = smoothRange(.12, 1, yawT);
  }
  return { left, right };
}

function tuftLookTransform() {
  const dir = Math.sign(state.yaw);
  const yawT = axisT(state.yaw);
  const pitchSign = Math.sign(state.pitch);
  const pitchT = axisT(state.pitch);
  const pitchData = pitchSign < 0 ? PITCH_UP : PITCH_DOWN;
  const yawDx = dir < 0 ? -21.7 * yawT : dir > 0 ? -10.3 * yawT : 0;
  const pitchDy = pitchData.tuftDy * pitchT;
  return translate(yawDx, pitchDy);
}

function lookStatus() {
  const yawText = state.yaw < 0 ? `左 ${Math.abs(state.yaw)}%` : state.yaw > 0 ? `右 ${state.yaw}%` : "中";
  const pitchText = state.pitch < 0 ? `上 ${Math.abs(state.pitch)}%` : state.pitch > 0 ? `下 ${state.pitch}%` : "中";
  return `看向 ${yawText} / ${pitchText}`;
}

function breathAmount(curve = THINKING_BREATH_CURVES.body) {
  const t = clamp(state.breathProgress, 0, 100) / 100;
  const base = Math.sin(Math.PI * t);
  const skew = curve?.skew || 0;
  const power = curve?.power || 1;
  const shifted = Math.max(0, base + skew * 0.32 * Math.sin(Math.PI * 2 * t));
  return clamp(Math.pow(shifted, power), 0, 1.18);
}

function bodyBreathPath(b) {
  const expand = state.bodyExpand * b;
  const topLift = state.bodyTopLift * b;
  const bottomDrop = state.bodyBottomDrop * b;
  const leftX = 60 - expand;
  const rightX = 314 + expand;
  const topY = 200 - topLift;
  const bottomY = 412 + bottomDrop * .35;
  const lowerCtrlY = 380 + bottomDrop;
  return [
    `M187 ${fmt(topY)}`,
    `C ${fmt(113 - expand * .58)} ${fmt(topY)} ${fmt(leftX)} 251 ${fmt(leftX)} 322`,
    `C ${fmt(leftX)} ${fmt(lowerCtrlY)} 101 ${fmt(bottomY)} 187 ${fmt(bottomY)}`,
    `C 273 ${fmt(bottomY)} ${fmt(rightX)} ${fmt(lowerCtrlY)} ${fmt(rightX)} 322`,
    `C ${fmt(rightX)} 251 ${fmt(261 + expand * .58)} ${fmt(topY)} 187 ${fmt(topY)}Z`
  ].join(" ");
}

function setLayerTransform(id, extraTransform) {
  const node = svg.querySelector(`#${id}`);
  if (!node) return;
  const transform = [baseTransform[id] || "", extraTransform].filter(Boolean).join(" ");
  if (transform) node.setAttribute("transform", transform);
  else node.removeAttribute("transform");
}

function applyTieBreathMotion(b) {
  const knotDx = state.tieKnotShift * b;
  const t = loopCycleProgress(state.loopDuration);
  const flutter = state.tieFlutter * Math.sin(Math.PI * 2 * t) * Math.sin(Math.PI * t);
  const swing = state.tieSwing * b + flutter;
  const knotMove = Math.abs(knotDx) < 1e-6 ? "" : `translate(${fmt(knotDx)} 0)`;
  const bladeSwing = Math.abs(knotDx) < 1e-6 && Math.abs(swing) < 1e-6
    ? ""
    : `${knotMove} rotate(${fmt(swing)} 34 14)`.trim();
  ["tie-knot", "tie-knot-highlight"].forEach((id) => setElementTransform(id, knotMove));
  ["tie-shadow", "tie-blade", "tie-center-fold", "tie-left-fold"].forEach((id) => setElementTransform(id, bladeSwing));
}

function handBreathTransform(side, data = null) {
  const b = breathAmount(THINKING_BREATH_CURVES.hand);
  const wobble = backHandWobbleMotion(side);
  const sideSign = side === "left" ? -1 : 1;
  const dx = sideSign * state.handOutward * b + wobble.x;
  const dy = state.handDrop * b + wobble.y;
  const pivot = data?.visibleRoot || data?.shoulder || HAND_AXES[side].root;
  return composeBreathTransforms(
    translate(dx, dy),
    rotateAroundPoint(wobble.rotate, pivot.x, pivot.y)
  );
}

function backHandWobbleMotion(side) {
  const t = clamp(state.breathProgress, 0, 100) / 100;
  const swing = Math.sin(Math.PI * 2 * t) * Math.sin(Math.PI * t);
  const lift = (1 - Math.cos(Math.PI * 4 * t)) / 2;
  const sideSign = side === "left" ? -1 : 1;
  return {
    x: sideSign * state.backHandWobbleX * swing,
    y: -state.backHandWobbleY * lift,
    rotate: sideSign * state.backHandWobbleRotate * swing
  };
}

function setElementTransform(id, extraTransform) {
  const node = svg.querySelector(`#${id}`);
  if (!node) return;
  const transform = [baseTransform[id] || "", extraTransform].filter(Boolean).join(" ");
  if (transform) node.setAttribute("transform", transform);
  else node.removeAttribute("transform");
}

function clearDiagnostics() {
  [
    "#arm-back-split-layer",
    "#body-cast-shadow-on-hand-layer",
    "#thinking-sticker-arm-layer",
    "#thinking-sticker-paw-layer",
    "#thinking-shoulder-edit-layer",
    "#thinking-front-hand-layer",
    "#thinking-thought-dots-layer",
    "#hand-front-split-layer",
    "#hand-body-occlusion-crease-layer",
    "#hand-sleeve-shadow-layer",
    "#hand-layer-split-guide"
  ].forEach((selector) => svg.querySelector(selector)?.remove());
  svg.querySelectorAll('[id^="split-clip-"], [id^="idle-hand-shadow-clip-"]').forEach((node) => node.remove());
}

function applyDim() {
  for (const selector of ["#ears-layer", "#head-layer", "#head-tufts", "#face-layer", "#tie", "#tail"]) {
    const node = svg.querySelector(selector);
    if (node) node.setAttribute("opacity", state.dimFace ? ".38" : "1");
  }
  const sunglasses = svg.querySelector("#sunglasses");
  if (sunglasses) {
    sunglasses.style.display = "";
    sunglasses.removeAttribute("display");
    sunglasses.setAttribute("opacity", state.dimFace ? ".38" : "1");
  }
}

function buildSideData(side) {
  const curve = buildCurve(side);
  const contact = findSleeveContact(curve);
  const sleeveAlong = clamp(contact.along + state.sleeveShift, 5, curve.L - 8);
  const sleeve = sampleCurve(curve, sleeveAlong);
  const tangent = normalize({ x: sleeve.ux, y: sleeve.uy });
  const normal = normalize({ x: -tangent.y, y: tangent.x });
  return {
    side,
    curve,
    sleeveAlong,
    sleeve,
    tangent,
    normal,
    shoulder: curve.joints.shoulder,
    visibleRoot: curve.joints.visibleRoot,
    elbow: curve.joints.elbow,
    wrist: curve.joints.wrist,
    tip: curve.joints.tip,
    contactAuto: contact
  };
}

function buildCurve(side) {
  const axis = axisGeometry(side);
  const baseVector = {
    x: axis.targetTip.x - axis.targetShoulder.x,
    y: axis.targetTip.y - axis.targetShoulder.y
  };
  const L = Math.hypot(baseVector.x, baseVector.y) || 1;
  const ux = baseVector.x / L;
  const uy = baseVector.y / L;
  const visibleRootT = axis.visibleRootT;
  const remainingT = 1 - visibleRootT;
  const elbowT = visibleRootT + remainingT * .4;
  const wristT = visibleRootT + remainingT * .72;
  const joints = {
    shoulder: axis.targetShoulder,
    visibleRoot: pointAtT(axis.targetShoulder, axis.targetTip, visibleRootT),
    elbow: pointAtT(axis.targetShoulder, axis.targetTip, elbowT),
    wrist: pointAtT(axis.targetShoulder, axis.targetTip, wristT),
    tip: axis.targetTip
  };
  const angles = handAngles(side);
  const armA = angles.arm * Math.PI / 180;
  const forearmA = angles.forearm * Math.PI / 180;
  const wristA = angles.wrist * Math.PI / 180;
  joints.visibleRoot = rotateAround(joints.visibleRoot, joints.shoulder, armA);
  joints.elbow = rotateAround(joints.elbow, joints.shoulder, armA);
  joints.wrist = rotateAround(joints.wrist, joints.shoulder, armA);
  joints.tip = rotateAround(joints.tip, joints.shoulder, armA);
  joints.wrist = rotateAround(joints.wrist, joints.elbow, forearmA);
  joints.tip = rotateAround(joints.tip, joints.elbow, forearmA);
  joints.tip = rotateAround(joints.tip, joints.wrist, wristA);

  const offsets = jointOffsets(side);
  joints.elbow = add(joints.elbow, offsets.elbow);
  joints.wrist = add(joints.wrist, offsets.wrist);
  joints.tip = add(joints.tip, offsets.wrist);

  const sourceVisibleRootAlong = state.shoulderDepth;
  const sourceRemaining = Math.max(1, axis.sourceL - sourceVisibleRootAlong);
  const sourceStops = [
    0,
    sourceVisibleRootAlong,
    sourceVisibleRootAlong + sourceRemaining * .4,
    sourceVisibleRootAlong + sourceRemaining * .72,
    axis.sourceL
  ];
  const jointCurve = buildJointCurve(joints, sourceStops);
  return {
    side,
    root: axis.targetShoulder,
    sourceRoot: axis.sourceShoulder,
    sourceUx: axis.sourceUx,
    sourceUy: axis.sourceUy,
    sourceL: axis.sourceL,
    visibleRoot: axis.sourceVisibleRoot,
    visibleRootAlong: jointCurve.targetStops[1],
    ux,
    uy,
    L: jointCurve.L,
    pts: jointCurve.pts,
    joints: jointCurve.joints,
    sourceStops,
    targetStops: jointCurve.targetStops
  };
}

function axisGeometry(side) {
  const visibleRoot = HAND_AXES[side].root;
  const tip = HAND_AXES[side].tip;
  const outward = normalize({ x: tip.x - visibleRoot.x, y: tip.y - visibleRoot.y });
  const sourceShoulder = {
    x: visibleRoot.x - outward.x * state.shoulderDepth,
    y: visibleRoot.y - outward.y * state.shoulderDepth
  };
  const targetShoulder = {
    x: sourceShoulder.x,
    y: sourceShoulder.y - state.shoulderLift
  };
  const sourceL = Math.hypot(tip.x - sourceShoulder.x, tip.y - sourceShoulder.y) || 1;
  return {
    sourceShoulder,
    sourceVisibleRoot: visibleRoot,
    sourceTip: tip,
    sourceUx: outward.x,
    sourceUy: outward.y,
    sourceL,
    targetShoulder,
    targetTip: tip,
    visibleRootT: clamp(state.shoulderDepth / sourceL, 0, 1)
  };
}

function handAngles(side) {
  if (side === "right" && state.mirror) {
    return { arm: -state.leftArm, forearm: -state.leftForearm, wrist: -state.leftWrist };
  }
  if (side === "right") return { arm: state.leftArm, forearm: state.leftForearm, wrist: state.leftWrist };
  return { arm: state.leftArm, forearm: state.leftForearm, wrist: state.leftWrist };
}

function jointOffsets(side) {
  const xFlip = side === "right" && state.mirror ? -1 : 1;
  return {
    elbow: { x: state.leftElbowX * xFlip, y: state.leftElbowY },
    wrist: { x: state.leftWristX * xFlip, y: state.leftWristY }
  };
}

function buildJointCurve(joints, sourceStops) {
  const ordered = [
    ["shoulder", joints.shoulder],
    ["visibleRoot", joints.visibleRoot],
    ["elbow", joints.elbow],
    ["wrist", joints.wrist],
    ["tip", joints.tip]
  ];
  const points = ordered.map((entry) => entry[1]);
  const roundness = {
    shoulder: .38,
    visibleRoot: .48,
    elbow: state.elbowRoundness,
    wrist: state.wristRoundness,
    tip: .24
  };
  const tangents = jointTangents(points);
  const pts = [];
  const jointAlong = {};
  let cumulative = 0;
  const addPoint = (key, point, tangent) => {
    const unit = normalize(tangent);
    if (pts.length) {
      const previous = pts[pts.length - 1];
      cumulative += Math.hypot(point.x - previous.x, point.y - previous.y);
    }
    const sample = { x: point.x, y: point.y, ux: unit.x, uy: unit.y, along: cumulative };
    pts.push(sample);
    if (key) jointAlong[key] = cumulative;
  };

  const samplesPerSegment = 28;
  for (let segment = 0; segment < points.length - 1; segment++) {
    const p1 = points[segment];
    const p2 = points[segment + 1];
    const key1 = ordered[segment][0];
    const key2 = ordered[segment + 1][0];
    const segLen = Math.hypot(p2.x - p1.x, p2.y - p1.y) || 1;
    const h1 = segLen * handleFactor(roundness[key1]);
    const h2 = segLen * handleFactor(roundness[key2]);
    const c1 = add(p1, scale(tangents[segment], h1));
    const c2 = add(p2, scale(tangents[segment + 1], -h2));
    for (let step = 0; step <= samplesPerSegment; step++) {
      if (segment > 0 && step === 0) continue;
      const t = step / samplesPerSegment;
      const key = step === 0
        ? key1
        : (step === samplesPerSegment ? key2 : null);
      addPoint(key, cubicBezier(p1, c1, c2, p2, t), cubicBezierTangent(p1, c1, c2, p2, t));
    }
  }

  const targetStops = ordered.map(([key]) => jointAlong[key]);
  return {
    pts,
    joints: Object.fromEntries(ordered.map(([key]) => [key, sampleCurveFromPoints(pts, jointAlong[key])])),
    L: cumulative,
    sourceStops,
    targetStops
  };
}

function jointTangents(points) {
  return points.map((point, index) => {
    if (index === 0) return normalize(sub(points[1], point));
    if (index === points.length - 1) return normalize(sub(point, points[index - 1]));
    const before = normalize(sub(point, points[index - 1]));
    const after = normalize(sub(points[index + 1], point));
    const blended = normalize(add(before, after));
    if (Math.abs(blended.x) + Math.abs(blended.y) < 1e-6) return after;
    return blended;
  });
}

function handleFactor(value) {
  return lerp(.08, .42, smooth01(value));
}

function cubicBezier(p0, p1, p2, p3, t) {
  const t2 = t * t;
  const t3 = t2 * t;
  const mt = 1 - t;
  const mt2 = mt * mt;
  const mt3 = mt2 * mt;
  return {
    x: p0.x * mt3 + 3 * p1.x * mt2 * t + 3 * p2.x * mt * t2 + p3.x * t3,
    y: p0.y * mt3 + 3 * p1.y * mt2 * t + 3 * p2.y * mt * t2 + p3.y * t3
  };
}

function cubicBezierTangent(p0, p1, p2, p3, t) {
  const mt = 1 - t;
  const t2 = t * t;
  return {
    x: 3 * mt * mt * (p1.x - p0.x) + 6 * mt * t * (p2.x - p1.x) + 3 * t2 * (p3.x - p2.x),
    y: 3 * mt * mt * (p1.y - p0.y) + 6 * mt * t * (p2.y - p1.y) + 3 * t2 * (p3.y - p2.y)
  };
}

function rotateAround(point, pivot, angle) {
  if (!angle) return { ...point };
  const dx = point.x - pivot.x;
  const dy = point.y - pivot.y;
  const c = Math.cos(angle);
  const s = Math.sin(angle);
  return {
    x: pivot.x + dx * c - dy * s,
    y: pivot.y + dx * s + dy * c
  };
}

function pointAtT(a, b, t) {
  return {
    x: lerp(a.x, b.x, t),
    y: lerp(a.y, b.y, t)
  };
}

function findSleeveContact(curve) {
  let previous = curve.pts[0];
  let previousInside = pointInPolygon(previous, bodyPolygon);
  for (let i = 1; i < curve.pts.length; i++) {
    const current = curve.pts[i];
    const currentInside = pointInPolygon(current, bodyPolygon);
    if (previousInside && !currentInside) {
      return {
        along: lerp(previous.along, current.along, .5),
        point: { x: (previous.x + current.x) / 2, y: (previous.y + current.y) / 2 },
        source: "body-exit"
      };
    }
    previous = current;
    previousInside = currentInside;
  }
  return {
    along: curve.L * .3,
    point: sampleCurve(curve, curve.L * .3),
    source: "fallback"
  };
}

function cloneShoulderPoints() {
  return Object.fromEntries(
    Object.entries(SHOULDER_POINT_DEFAULTS).map(([id, point]) => [id, { ...point }])
  );
}

function drawThinkingSticker(armLayer, pawLayer, shoulderEditLayer) {
  if (!state.thinkingStickerVisible) return;
  const armTransform = thinkingStickerTransform("arm");
  const pawTransform = thinkingStickerTransform("paw");
  const shoulderTransform = shoulderLocalTransform();

  const armGroup = el("g", {
    "data-role": "thinking-png-arm-sticker",
    opacity: state.thinkingStickerOpacity
  });
  if (armTransform) armGroup.setAttribute("transform", armTransform);
  if (state.thinkingShoulderVisible) {
    const shoulderBulge = el("path", {
      d: shoulderBulgePath(),
      fill: "#fff8f0",
      opacity: ".98",
      "data-role": "thinking-outer-shoulder-bulge",
      transform: shoulderTransform
    });
    armGroup.appendChild(shoulderBulge);
  }
  armGroup.appendChild(stickerImage(THINKING_ARM_PATCH));
  armLayer.appendChild(armGroup);
  drawShoulderEditor(shoulderEditLayer, armTransform, shoulderTransform);

  const pawGroup = el("g", {
    "data-role": "thinking-png-paw-sticker",
    opacity: state.thinkingStickerOpacity
  });
  if (pawTransform) pawGroup.setAttribute("transform", pawTransform);
  const pawNudge = composeBreathTransforms(translate(state.thinkingStickerPawX, state.thinkingStickerPawY));
  const pawInner = el("g");
  if (pawNudge) pawInner.setAttribute("transform", pawNudge);
  pawInner.appendChild(stickerImage(THINKING_PAW_PATCH));
  pawGroup.appendChild(pawInner);
  pawLayer.appendChild(pawGroup);
}

function thinkingStickerTransform(kind = "arm") {
  const b = breathAmount(kind === "paw" ? THINKING_BREATH_CURVES.paw : THINKING_BREATH_CURVES.hand);
  const exhale = 1 - b;
  const wobble = kind === "paw" ? pawWobbleMotion() : { x: 0, y: 0, rotate: 0 };
  const xBind = kind === "paw" ? state.stickerPawExhaleX * exhale + wobble.x : 0;
  const yBind = kind === "paw"
    ? state.stickerPawExhaleDrop * exhale + wobble.y
    : state.stickerArmExhaleDrop * exhale;
  const rotation = state.thinkingStickerRotate + wobble.rotate;
  const rotationTransform = kind === "paw"
    ? rotateAroundPoint(rotation, THINKING_PAW_PATCH_CENTER.x, THINKING_PAW_PATCH_CENTER.y)
    : rotateAroundPoint(rotation, 0, 0);
  return composeBreathTransforms(
    translate(state.thinkingStickerX + xBind, state.thinkingStickerY - 0.5 + yBind),
    rotationTransform,
    Math.abs(state.thinkingStickerScale - 1) < 1e-6 ? "" : `scale(${fmt(state.thinkingStickerScale)})`
  );
}

function pawWobbleMotion() {
  const t = clamp(state.breathProgress, 0, 100) / 100;
  const swing = Math.sin(Math.PI * 2 * t) * Math.sin(Math.PI * t);
  const lift = (1 - Math.cos(Math.PI * 4 * t)) / 2;
  return {
    x: state.stickerPawWobbleX * swing,
    y: -state.stickerPawWobbleY * lift,
    rotate: state.stickerPawWobbleRotate * swing
  };
}

function shoulderLocalTransform() {
  return composeBreathTransforms(
    translate(state.thinkingShoulderX, state.thinkingShoulderY),
    scaleAroundStickerPin(
      THINKING_SHOULDER_PIN.x,
      THINKING_SHOULDER_PIN.y,
      state.thinkingShoulderScaleX,
      state.thinkingShoulderScaleY
    )
  );
}

function stickerImage(asset) {
  const source = THINKING_STICKER_SOURCE;
  const scale = source.scale;
  const crop = asset.crop;
  const node = el("image", {
    href: asset.href,
    x: fmt((crop.x - source.anchor.x) * scale),
    y: fmt((crop.y - source.anchor.y) * scale),
    width: fmt(crop.w * scale),
    height: fmt(crop.h * scale),
    preserveAspectRatio: "none",
    draggable: "false"
  });
  node.setAttributeNS("http://www.w3.org/1999/xlink", "href", asset.href);
  return node;
}

function drawThoughtDots(layer) {
  if (!state.thoughtDotsVisible || !layer) return;
  const progress = loopCycleProgress(state.thoughtDotsCycle) * 100;
  const palette = THOUGHT_DOT_PALETTES[state.thoughtDotsPalette] || THOUGHT_DOT_PALETTES.mist;
  const dots = [
    { x: 256, y: 38, r: 7.1, start: 8, peak: 24, fade: 76, end: 91 },
    { x: 282, y: 38, r: 7.1, start: 24, peak: 40, fade: 80, end: 94 },
    { x: 308, y: 38, r: 7.1, start: 40, peak: 56, fade: 84, end: 97 }
  ];
  const group = el("g", {
    "data-role": "thinking-thought-dots",
    transform: composeBreathTransforms(
      translate(state.thoughtDotsX, state.thoughtDotsY),
      scaleAroundStickerPin(282, 38, state.thoughtDotsScale, state.thoughtDotsScale)
    )
  });
  dots.forEach((dot, index) => {
    const amount = thoughtDotAmount(progress, dot);
    if (amount <= .015) return;
    const floatY = -state.thoughtDotsFloat * amount * (.65 + index * .18);
    const pulse = Math.sin(Math.PI * amount);
    const radius = dot.r * lerp(.78, 1, amount) * (1 + pulse * .05);
    const opacity = state.thoughtDotsOpacity * amount;
    group.appendChild(el("circle", {
      cx: fmt(dot.x + amount * (1.4 + index * .6)),
      cy: fmt(dot.y + floatY),
      r: fmt(radius),
      fill: palette.fill,
      opacity: fmt(opacity)
    }));
    group.appendChild(el("circle", {
      cx: fmt(dot.x + amount * (1.4 + index * .6) - radius * .22),
      cy: fmt(dot.y + floatY - radius * .25),
      r: fmt(radius * .28),
      fill: palette.shine,
      opacity: fmt(opacity * .34)
    }));
  });
  layer.appendChild(group);
}

function thoughtDotAmount(progress, dot) {
  if (progress < dot.start || progress > dot.end) return 0;
  if (progress < dot.peak) return smooth01((progress - dot.start) / (dot.peak - dot.start));
  if (progress < dot.fade) return 1;
  return 1 - smooth01((progress - dot.fade) / (dot.end - dot.fade));
}

function shoulderBulgePath() {
  const p = state.shoulderPoints;
  return [
    `M ${fmt(p.start.x)} ${fmt(p.start.y)}`,
    `C ${fmt(p.c1.x)} ${fmt(p.c1.y)} ${fmt(p.c2.x)} ${fmt(p.c2.y)} ${fmt(p.p1.x)} ${fmt(p.p1.y)}`,
    `C ${fmt(p.c3.x)} ${fmt(p.c3.y)} ${fmt(p.c4.x)} ${fmt(p.c4.y)} ${fmt(p.p2.x)} ${fmt(p.p2.y)}`,
    `C ${fmt(p.c5.x)} ${fmt(p.c5.y)} ${fmt(p.c6.x)} ${fmt(p.c6.y)} ${fmt(p.p3.x)} ${fmt(p.p3.y)}`,
    `C ${fmt(p.c7.x)} ${fmt(p.c7.y)} ${fmt(p.c8.x)} ${fmt(p.c8.y)} ${fmt(p.start.x)} ${fmt(p.start.y)} Z`
  ].join(" ");
}

function drawShoulderEditor(layer, stickerTransform, shoulderTransform) {
  if (!state.thinkingShoulderVisible || !state.thinkingShoulderEdit || !layer) return;
  const group = el("g", { "data-role": "thinking-shoulder-editor" });
  if (stickerTransform) group.setAttribute("transform", stickerTransform);
  const local = el("g", { "data-role": "thinking-shoulder-editor-local" });
  if (shoulderTransform) local.setAttribute("transform", shoulderTransform);

  const p = state.shoulderPoints;
  [
    ["start", "c1"], ["p1", "c2"], ["p1", "c3"], ["p2", "c4"],
    ["p2", "c5"], ["p3", "c6"], ["p3", "c7"], ["start", "c8"]
  ].forEach(([a, c]) => {
    local.appendChild(el("path", {
      d: `M ${fmt(p[a].x)} ${fmt(p[a].y)} L ${fmt(p[c].x)} ${fmt(p[c].y)}`,
      fill: "none",
      stroke: "#6d56a7",
      "stroke-width": "1",
      "stroke-dasharray": "3 3",
      opacity: ".65",
      "pointer-events": "none"
    }));
  });

  Object.entries(p).forEach(([id, point]) => {
    const isAnchor = SHOULDER_ANCHOR_POINTS.has(id);
    const handle = el("circle", {
      cx: point.x,
      cy: point.y,
      r: isAnchor ? 4.2 : 3.1,
      fill: isAnchor ? "#fffaf3" : "#6d56a7",
      stroke: isAnchor ? "#2f241c" : "#fffaf3",
      "stroke-width": isAnchor ? "1.5" : "1.1",
      cursor: "move",
      "data-shoulder-point": id
    });
    handle.addEventListener("pointerdown", (event) => startShoulderPointDrag(event, id));
    local.appendChild(handle);
  });

  group.appendChild(local);
  layer.appendChild(group);
}

function startShoulderPointDrag(event, pointId) {
  event.preventDefault();
  event.stopPropagation();
  const localGroup = event.currentTarget.closest('[data-role="thinking-shoulder-editor-local"]');
  const matrix = localGroup?.getScreenCTM()?.inverse();
  if (!matrix || !svg) return;
  const point = svg.createSVGPoint();
  const move = (moveEvent) => {
    moveEvent.preventDefault();
    point.x = moveEvent.clientX;
    point.y = moveEvent.clientY;
    const local = point.matrixTransform(matrix);
    state.shoulderPoints[pointId] = {
      x: Number(fmt(clamp(local.x, -165, 12))),
      y: Number(fmt(clamp(local.y, -20, 125)))
    };
    render();
  };
  const up = () => {
    window.removeEventListener("pointermove", move);
    window.removeEventListener("pointerup", up);
    window.removeEventListener("pointercancel", up);
  };
  window.addEventListener("pointermove", move);
  window.addEventListener("pointerup", up);
  window.addEventListener("pointercancel", up);
}

function scaleAroundStickerPin(x, y, sx, sy) {
  if (Math.abs(sx - 1) < 1e-6 && Math.abs(sy - 1) < 1e-6) return "";
  return `translate(${fmt(x)} ${fmt(y)}) scale(${fmt(sx)} ${fmt(sy)}) translate(${fmt(-x)} ${fmt(-y)})`;
}

function drawThinkingFrontHand(layer) {
  if (!state.thinkingHandVisible) return;
  const group = el("g", {
    "data-role": "thinking-front-chin-paw",
    "data-layer-mode": state.thinkingHandTopPreview ? "temporary-top-preview" : "formal-under-face"
  });
  const b = breathAmount(THINKING_BREATH_CURVES.hand);
  const transform = composeBreathTransforms(
    translate(state.thinkingHandX, state.thinkingHandY - b * 0.6),
    Math.abs(state.thinkingHandRotate) < 1e-6 ? "" : `rotate(${fmt(state.thinkingHandRotate)})`,
    Math.abs(state.thinkingHandScale - 1) < 1e-6 ? "" : `scale(${fmt(state.thinkingHandScale)})`
  );
  if (transform) group.setAttribute("transform", transform);

  const L = clamp(state.thinkingArmLength, 44, 118);
  const bend = clamp(state.thinkingArmBend, -34, 34);
  const armD = [
    `M ${fmt(-L)} ${fmt(42)}`,
    `C ${fmt(-L * .86)} ${fmt(18 + bend * .2)} ${fmt(-L * .48)} ${fmt(2 - bend * .18)} -18 3`,
    `C -5 4 -1 15 -10 24`,
    `C ${fmt(-25)} ${fmt(47 + bend * .18)} ${fmt(-55)} ${fmt(64 + bend * .14)} ${fmt(-L + 6)} 58`,
    `C ${fmt(-L - 4)} 56 ${fmt(-L - 7)} 47 ${fmt(-L)} 42 Z`
  ].join(" ");
  group.appendChild(el("path", {
    d: armD,
    fill: "#fff8f0",
    stroke: "#eadccf",
    "stroke-width": "2.2",
    "stroke-linejoin": "round",
    opacity: ".98"
  }));

  const creaseD = `M ${fmt(-L + 12)} ${fmt(53)} C ${fmt(-L * .62)} ${fmt(70 + bend * .18)} ${fmt(-34)} ${fmt(49 - bend * .08)} -10 22`;
  group.appendChild(el("path", {
    d: creaseD,
    fill: "none",
    stroke: "#e6d7c6",
    "stroke-width": "2.4",
    "stroke-linecap": "round",
    opacity: ".55"
  }));

  const paw = el("g", {
    transform: composeBreathTransforms(
      translate(state.thinkingPawX, state.thinkingPawY),
      Math.abs(state.thinkingPawRotate) < 1e-6 ? "" : `rotate(${fmt(state.thinkingPawRotate)})`,
      Math.abs(state.thinkingPawScale - 1) < 1e-6 ? "" : `scale(${fmt(state.thinkingPawScale)})`
    )
  });
  paw.appendChild(el("path", {
    d: "M -7 -18 C 7 -22 23 -12 26 2 C 30 18 14 31 -4 29 C -21 27 -32 12 -28 -3 C -25 -14 -18 -17 -7 -18 Z",
    fill: "#d8a686"
  }));
  paw.appendChild(el("path", {
    d: "M -9 -12 C 3 -16 17 -10 20 1",
    fill: "none",
    stroke: "#e4b58f",
    "stroke-width": "2.3",
    "stroke-linecap": "round",
    opacity: ".35"
  }));
  group.appendChild(paw);

  if (state.showGuides) {
    group.appendChild(el("circle", { cx: "0", cy: "0", r: "3", fill: "#6d56a7", opacity: ".65" }));
  }

  layer.appendChild(group);
}

function drawCompleteHand(layer, side, data) {
  const group = el("g", { "data-role": "complete-idle-back-hand" });
  const transform = handBreathTransform(side, data);
  if (transform) group.setAttribute("transform", transform);
  HAND_IDS[side].forEach((id, idx) => {
    const source = svg.querySelector(`#${id}`);
    if (!source || !baseD[id]) return;
    const path = el("path", {
      d: denseWarpPathSmooth(baseD[id], (point) => bendPoint(data.curve, point), idx === 0 ? 3 : 1),
      fill: source.getAttribute("fill") || "#fff8f0"
    });
    if (state.shadowMode === "stroke" || state.shadowMode === "combo") {
      path.setAttribute("stroke", "#c69a76");
      path.setAttribute("stroke-width", "1.6");
      path.setAttribute("stroke-linejoin", "round");
      path.setAttribute("stroke-opacity", fmt(clamp(state.shadowPower * 1.4, 0, .85)));
    }
    group.appendChild(path);
  });
  layer.appendChild(group);
}

function drawFrontRootArm(layer, side, data) {
  const length = clamp(state.frontRootLength || 0, 0, 110);
  if (length <= 0) return;
  const startAlong = data.curve.targetStops[1] ?? data.sleeveAlong;
  const endAlong = clamp(startAlong + length, startAlong + 2, data.curve.L);
  const halfWidth = 18.5;
  const steps = Math.max(4, Math.ceil(length / 5));
  const upper = [];
  const lower = [];
  for (let i = 0; i <= steps; i++) {
    const sample = sampleCurve(data.curve, lerp(startAlong, endAlong, i / steps));
    const normal = normalize({ x: -sample.uy, y: sample.ux });
    upper.push(add(sample, scale(normal, halfWidth)));
    lower.push(add(sample, scale(normal, -halfWidth)));
  }
  const cap = sampleCurve(data.curve, endAlong);
  const capNormal = normalize({ x: -cap.uy, y: cap.ux });
  const d = [
    `M ${fmt(upper[0].x)} ${fmt(upper[0].y)}`,
    ...upper.slice(1).map((point) => `L ${fmt(point.x)} ${fmt(point.y)}`),
    `C ${fmt(add(upper[upper.length - 1], scale({ x: cap.ux, y: cap.uy }, halfWidth * .55)).x)} ${fmt(add(upper[upper.length - 1], scale({ x: cap.ux, y: cap.uy }, halfWidth * .55)).y)} ${fmt(add(lower[lower.length - 1], scale({ x: cap.ux, y: cap.uy }, halfWidth * .55)).x)} ${fmt(add(lower[lower.length - 1], scale({ x: cap.ux, y: cap.uy }, halfWidth * .55)).y)} ${fmt(lower[lower.length - 1].x)} ${fmt(lower[lower.length - 1].y)}`,
    ...lower.slice(0, -1).reverse().map((point) => `L ${fmt(point.x)} ${fmt(point.y)}`),
    "Z"
  ].join(" ");
  const group = el("g", { "data-role": "idle-front-root-arm" });
  group.appendChild(el("path", {
    d,
    fill: "#fff8f0"
  }));
  const creaseStart = sampleCurve(data.curve, clamp(startAlong + length * .12, 0, data.curve.L));
  const creaseEnd = sampleCurve(data.curve, clamp(startAlong + length * .72, 0, data.curve.L));
  const creaseD = `M ${fmt(creaseStart.x)} ${fmt(creaseStart.y)} Q ${fmt((creaseStart.x + creaseEnd.x) / 2)} ${fmt((creaseStart.y + creaseEnd.y) / 2 - 4)} ${fmt(creaseEnd.x)} ${fmt(creaseEnd.y)}`;
  group.appendChild(el("path", {
    d: creaseD,
    fill: "none",
    stroke: "#e8d8c7",
    "stroke-width": "2.2",
    "stroke-linecap": "round",
    opacity: ".45"
  }));
  layer.appendChild(group);
}

function drawBackHandReference(layer, side, data) {
  const baseId = HAND_IDS[side][0];
  if (!baseD[baseId]) return;
  const transform = handBreathTransform(side, data);
  const attrs = {
    d: denseWarpPathSmooth(baseD[baseId], (point) => bendPoint(data.curve, point), 3),
    fill: "none",
    stroke: "#8f7b68",
    "stroke-width": "1.8",
    "stroke-dasharray": "5 4",
    "stroke-linejoin": "round",
    opacity: ".72"
  };
  if (transform) attrs.transform = transform;
  layer.appendChild(el("path", attrs));
}

function drawSleeveShadow(layer, data) {
  if (state.shadowPower <= 0 || state.shadowMode === "none") return;
  if (state.shadowMode === "drop") {
    const clipId = ensureBodyClip();
    const g = el("g", {
      "clip-path": `url(#${clipId})`,
      "data-role": "sleeve-shadow",
      "data-shadow-mode": "idle-entry-fill"
    });
    drawIdleEntryShadow(g, data);
    layer.appendChild(g);
    return;
  }
  const clipId = ensureBodyClip();
  const group = el("g", {
    "clip-path": `url(#${clipId})`,
    "data-role": "sleeve-shadow",
    "data-shadow-mode": state.shadowMode
  });
  if (state.shadowMode === "contact" || state.shadowMode === "combo") {
    drawEntryCrease(group, data);
    drawInnerArmEdgeShadow(group, data);
  }
  layer.appendChild(group);
}

function drawEntryCrease(group, data) {
  const c = data.sleeve;
  const tangent = data.tangent;
  const inward = normalize({ x: data.shoulder.x - c.x, y: data.shoulder.y - c.y });
  const a = add(c, scale(tangent, -18));
  const b = add(c, scale(tangent, 18));
  const q = add(c, scale(inward, 8));
  const d = `M ${fmt(a.x)} ${fmt(a.y)} Q ${fmt(q.x)} ${fmt(q.y)} ${fmt(b.x)} ${fmt(b.y)}`;
  group.appendChild(el("path", {
    d,
    fill: "none",
    stroke: "#bda38c",
    "stroke-width": "11",
    "stroke-linecap": "round",
    opacity: fmt(state.shadowPower * .36)
  }));
  group.appendChild(el("path", {
    d,
    fill: "none",
    stroke: "#9a6d4f",
    "stroke-width": "4.2",
    "stroke-linecap": "round",
    opacity: fmt(state.shadowPower * .55)
  }));
}

function drawPawBackShadow(group, data) {
  const wristAlong = data.curve.targetStops[3] ?? data.sleeveAlong + 70;
  const tipAlong = data.curve.targetStops[4] ?? data.curve.L;
  const base = sampleCurve(data.curve, lerp(wristAlong, tipAlong, .18));
  const bodySide = normalize({ x: 187 - base.x, y: 292 - base.y });
  const center = add(base, scale(bodySide, 11));
  const darkCenter = add(center, scale(bodySide, 3));
  const angle = Math.atan2(base.uy, base.ux) * 180 / Math.PI;
  group.appendChild(el("ellipse", {
    cx: fmt(center.x),
    cy: fmt(center.y),
    rx: "26",
    ry: "8.5",
    fill: "#b89475",
    opacity: fmt(state.shadowPower * .48),
    transform: `rotate(${fmt(angle)} ${fmt(center.x)} ${fmt(center.y)})`
  }));
  group.appendChild(el("ellipse", {
    cx: fmt(darkCenter.x),
    cy: fmt(darkCenter.y),
    rx: "15",
    ry: "4.2",
    fill: "#8e6045",
    opacity: fmt(state.shadowPower * .34),
    transform: `rotate(${fmt(angle)} ${fmt(center.x)} ${fmt(center.y)})`
  }));
}

function drawInnerArmEdgeShadow(group, data) {
  // 居中暗带:沿手臂中线居中盖一条暗影,宽度窄于面条宽(37),两侧各露白边
  const start = clamp(data.sleeveAlong + 4, 0, data.curve.L);
  const tipAlong = data.curve.targetStops[4] != null ? data.curve.targetStops[4] : data.curve.L;
  const end = clamp(tipAlong - 4, start + 8, data.curve.L);
  const points = [];
  const steps = 16;
  for (let i = 0; i <= steps; i++) {
    points.push(sampleCurve(data.curve, lerp(start, end, i / steps)));
  }
  const d = pathFromPoints(points, false);
  group.appendChild(el("path", {
    d,
    fill: "none",
    stroke: "#c4a588",
    "stroke-width": "21",
    "stroke-linecap": "round",
    "stroke-linejoin": "round",
    opacity: fmt(state.shadowPower * .30)
  }));
  group.appendChild(el("path", {
    d,
    fill: "none",
    stroke: "#a97e60",
    "stroke-width": "10",
    "stroke-linecap": "round",
    "stroke-linejoin": "round",
    opacity: fmt(state.shadowPower * .28)
  }));
}

function drawIdleEntryShadow(group, data) {
  const startAlong = data.curve.targetStops[1] ?? data.sleeveAlong;
  const rootLength = clamp(state.frontRootLength || 44, 0, 110);
  const entryAlong = clamp(startAlong + rootLength * .82, startAlong + 4, data.curve.L);
  const entry = sampleCurve(data.curve, entryAlong);
  const tangent = normalize({ x: entry.ux, y: entry.uy });
  const normal = normalize({ x: -entry.uy, y: entry.ux });
  const inward = normalize({ x: 187 - entry.x, y: 318 - entry.y });
  const half = 13;
  const width = clamp(rootLength * .42, 14, 24);
  const center = add(entry, scale(inward, 8));
  const a = add(add(center, scale(normal, -half)), scale(tangent, -width * .18));
  const b = add(add(center, scale(normal, half)), scale(tangent, -width * .18));
  const c = add(add(center, scale(normal, half * .74)), scale(inward, 11));
  const d = add(add(center, scale(normal, -half * .74)), scale(inward, 11));
  const softD = [
    `M ${fmt(a.x)} ${fmt(a.y)}`,
    `C ${fmt(add(a, scale(inward, 6)).x)} ${fmt(add(a, scale(inward, 6)).y)} ${fmt(add(d, scale(normal, -2)).x)} ${fmt(add(d, scale(normal, -2)).y)} ${fmt(d.x)} ${fmt(d.y)}`,
    `L ${fmt(c.x)} ${fmt(c.y)}`,
    `C ${fmt(add(c, scale(normal, 2)).x)} ${fmt(add(c, scale(normal, 2)).y)} ${fmt(add(b, scale(inward, 6)).x)} ${fmt(add(b, scale(inward, 6)).y)} ${fmt(b.x)} ${fmt(b.y)}`,
    "Z"
  ].join(" ");
  group.appendChild(el("path", {
    d: softD,
    fill: "#c6ab93",
    opacity: fmt(clamp(state.shadowPower * .32, 0, .32))
  }));

  const coreCenter = add(center, scale(inward, 4));
  const coreHalf = half * .55;
  const coreA = add(coreCenter, scale(normal, -coreHalf));
  const coreB = add(coreCenter, scale(normal, coreHalf));
  const coreC = add(add(coreCenter, scale(normal, coreHalf * .7)), scale(inward, 5.5));
  const coreD = add(add(coreCenter, scale(normal, -coreHalf * .7)), scale(inward, 5.5));
  group.appendChild(el("path", {
    d: [
      `M ${fmt(coreA.x)} ${fmt(coreA.y)}`,
      `Q ${fmt(add(coreD, scale(inward, 1)).x)} ${fmt(add(coreD, scale(inward, 1)).y)} ${fmt(coreD.x)} ${fmt(coreD.y)}`,
      `L ${fmt(coreC.x)} ${fmt(coreC.y)}`,
      `Q ${fmt(add(coreC, scale(inward, -1)).x)} ${fmt(add(coreC, scale(inward, -1)).y)} ${fmt(coreB.x)} ${fmt(coreB.y)}`,
      "Z"
    ].join(" "),
    fill: "#8e6045",
    opacity: fmt(clamp(state.shadowPower * .36, 0, .34))
  }));
}

function drawBodyCastShadowOnHand(layer, side, data) {
  if (state.shadowMode === "none" || state.shadowPower <= 0) return;
  if (!bodyPolygon.length) return;
  const ys = [244, 252, 262, 274, 288, 304, 320, 334];
  const seamPoints = ys
    .map((y) => bodySidePoint(side, y, -1.6))
    .filter(Boolean);
  if (seamPoints.length < 3) return;
  const d = pathFromPoints(seamPoints, false);
  const clipId = ensureWarpedHandClip(side, data);
  const softWidth = clamp(7 + (state.shadowStroke || 2.5) * .8, 7, 14);
  const coreWidth = clamp(2.4 + (state.shadowStroke || 2.5) * .32, 2.4, 5);
  const group = el("g", {
    "clip-path": `url(#${clipId})`,
    "data-role": "idle-body-cast-shadow-on-hand"
  });
  group.appendChild(el("path", {
    d,
    fill: "none",
    stroke: "#c9ad95",
    "stroke-width": fmt(softWidth),
    "stroke-linejoin": "round",
    "stroke-linecap": "round",
    opacity: fmt(clamp(state.shadowPower * .24, 0, .18))
  }));
  group.appendChild(el("path", {
    d,
    fill: "none",
    stroke: "#a77d5f",
    "stroke-width": fmt(coreWidth),
    "stroke-linejoin": "round",
    "stroke-linecap": "round",
    opacity: fmt(clamp(state.shadowPower * .32, 0, .24))
  }));
  layer.appendChild(group);
}

function ensureWarpedHandClip(side, data) {
  const defs = ensureDefs();
  const id = `idle-hand-shadow-clip-${side}`;
  svg.querySelector(`#${id}`)?.remove();
  const clip = el("clipPath", { id, clipPathUnits: "userSpaceOnUse" });
  const transform = handBreathTransform(side, data);
  HAND_IDS[side].forEach((pathId, index) => {
    if (!baseD[pathId]) return;
    const attrs = {
      d: denseWarpPathSmooth(baseD[pathId], (point) => bendPoint(data.curve, point), index === 0 ? 3 : 1)
    };
    if (transform) attrs.transform = transform;
    clip.appendChild(el("path", attrs));
  });
  defs.appendChild(clip);
  return id;
}

function bodySidePoint(side, y, inset) {
  const xs = [];
  for (let i = 0, j = bodyPolygon.length - 1; i < bodyPolygon.length; j = i++) {
    const a = bodyPolygon[j];
    const b = bodyPolygon[i];
    if ((a.y <= y && b.y > y) || (b.y <= y && a.y > y)) {
      const t = (y - a.y) / ((b.y - a.y) || 1e-9);
      xs.push(lerp(a.x, b.x, t));
    }
  }
  if (xs.length < 2) return null;
  xs.sort((a, b) => a - b);
  const edgeX = side === "left" ? xs[0] : xs[xs.length - 1];
  const direction = side === "left" ? 1 : -1;
  return { x: edgeX + direction * inset, y };
}

// 把描边折线按「在身体内」切成若干段,在身体边界处用交点精确截断(几何裁断,末端干净)。
// 露出身体外的部分既不画、也不沿身体边桥接。调用方不要再套 body clip。
function clipContourInside(pts, poly) {
  if (!poly || poly.length < 3) return [pts];
  const inside = pts.map((p) => pointInPolygon(p, poly));
  const runs = [];
  let cur = null;
  for (let i = 0; i < pts.length; i++) {
    if (inside[i]) {
      if (!cur) {
        cur = [];
        if (i > 0 && !inside[i - 1]) {                       // 从身体外进入:起点截到交点
          const x = firstPolyCross(pts[i - 1], pts[i], poly);
          if (x) cur.push(x.point);
        }
      }
      cur.push(pts[i]);
    } else if (cur) {
      const x = firstPolyCross(pts[i - 1], pts[i], poly);    // 走出身体:终点截到交点
      if (x) cur.push(x.point);
      if (cur.length >= 2) runs.push(cur);
      cur = null;
    }
  }
  if (cur && cur.length >= 2) runs.push(cur);
  return runs;
}

function firstPolyCross(a, b, poly) {
  let best = null, bestT = Infinity;
  for (let e = 0; e < poly.length; e++) {
    const x = segSegCross(a, b, poly[e], poly[(e + 1) % poly.length]);
    if (x && x.t < bestT) { bestT = x.t; best = { point: x.point, edge: e }; }
  }
  return best;
}

function segSegCross(p1, p2, p3, p4) {
  const d1x = p2.x - p1.x, d1y = p2.y - p1.y;
  const d2x = p4.x - p3.x, d2y = p4.y - p3.y;
  const den = d1x * d2y - d1y * d2x;
  if (Math.abs(den) < 1e-9) return null;
  const t = ((p3.x - p1.x) * d2y - (p3.y - p1.y) * d2x) / den;
  const u = ((p3.x - p1.x) * d1y - (p3.y - p1.y) * d1x) / den;
  if (t >= -1e-6 && t <= 1 + 1e-6 && u >= -1e-6 && u <= 1 + 1e-6) {
    return { point: { x: p1.x + t * d1x, y: p1.y + t * d1y }, t };
  }
  return null;
}

function smoothClosed(pts, passes) {
  let out = pts;
  for (let k = 0; k < passes; k++) {
    const n = out.length;
    const next = [];
    for (let i = 0; i < n; i++) {
      const a = out[(i - 1 + n) % n];
      const b = out[i];
      const c = out[(i + 1) % n];
      next.push({ x: (a.x + 2 * b.x + c.x) / 4, y: (a.y + 2 * b.y + c.y) / 4 });
    }
    out = next;
  }
  return out;
}

function drawGuides(layer, side, data) {
  layer.appendChild(el("path", {
    d: curveD(data.curve),
    fill: "none",
    stroke: "#14776c",
    "stroke-width": "2.4",
    "stroke-dasharray": "8 7",
    "stroke-linecap": "round",
    opacity: ".78"
  }));
  const points = [
    ["S", data.shoulder, "#7a6b5d", 5],
    ["R", data.visibleRoot, "#3c3026", 6],
    ["E", data.elbow, "#df862e", 5],
    ["W", data.wrist, "#1c9a8c", 5],
    ["T", data.tip, "#ad4938", 6],
    ["C", data.sleeve, "#6d56a7", 7]
  ];
  points.forEach(([label, point, fill, radius]) => {
    layer.appendChild(el("circle", {
      cx: fmt(point.x),
      cy: fmt(point.y),
      r: radius,
      fill,
      stroke: "#fffaf3",
      "stroke-width": "2"
    }));
    const text = el("text", {
      x: fmt(point.x),
      y: fmt(point.y + (label === "C" || label === "S" ? -18 : 22)),
      fill,
      "font-size": "12",
      "font-weight": "700",
      "text-anchor": "middle",
      "paint-order": "stroke",
      stroke: "#fffaf3",
      "stroke-width": "3"
    });
    text.textContent = `${side === "left" ? "L" : "R"}${label}`;
    layer.appendChild(text);
  });
}

function makeClipPair(side, data) {
  const defs = ensureDefs();
  const big = 900;
  const t = data.tangent;
  const n = data.normal;
  const frontCenter = add(data.sleeve, scale(t, -state.frontOverlap));
  const backCenter = add(data.sleeve, scale(t, state.frontOverlap));
  const frontPoints = [
    add(frontCenter, scale(n, big)),
    add(frontCenter, scale(n, -big)),
    add(add(frontCenter, scale(n, -big)), scale(t, big)),
    add(add(frontCenter, scale(n, big)), scale(t, big))
  ];
  const backPoints = [
    add(backCenter, scale(n, big)),
    add(backCenter, scale(n, -big)),
    add(add(backCenter, scale(n, -big)), scale(t, -big)),
    add(add(backCenter, scale(n, big)), scale(t, -big))
  ];
  defs.appendChild(clipPolygon(`split-clip-${side}-front`, frontPoints));
  defs.appendChild(clipPolygon(`split-clip-${side}-back`, backPoints));
}

function clipPolygon(id, points) {
  const clip = el("clipPath", { id, clipPathUnits: "userSpaceOnUse" });
  clip.appendChild(el("polygon", {
    points: points.map((point) => `${fmt(point.x)},${fmt(point.y)}`).join(" ")
  }));
  return clip;
}

function ensureBodyClip() {
  const defs = ensureDefs();
  let clip = svg.querySelector("#split-clip-body");
  if (!clip) {
    const body = svg.querySelector("#body-belly-fill");
    clip = el("clipPath", { id: "split-clip-body", clipPathUnits: "userSpaceOnUse" });
    clip.appendChild(el("path", { d: body.getAttribute("d") }));
    defs.appendChild(clip);
  }
  return "split-clip-body";
}

function ensureDefs() {
  let defs = svg.querySelector("defs");
  if (!defs) {
    defs = el("defs");
    svg.insertBefore(defs, svg.firstChild);
  }
  return defs;
}

function bendPoint(curve, point) {
  const vx = point.x - curve.sourceRoot.x;
  const vy = point.y - curve.sourceRoot.y;
  const acrossAxis = { x: -curve.sourceUy, y: curve.sourceUx };
  const sourceAlong = vx * curve.sourceUx + vy * curve.sourceUy;
  const along = mapAlong(sourceAlong, curve.sourceStops, curve.targetStops);
  const across = vx * acrossAxis.x + vy * acrossAxis.y;
  const sampled = sampleCurve(curve, along);
  const normal = { x: -sampled.uy, y: sampled.ux };
  return {
    x: sampled.x + normal.x * across,
    y: sampled.y + normal.y * across
  };
}

function sampleCurve(curve, along) {
  return sampleCurveFromPoints(curve.pts, clamp(along, 0, curve.L));
}

function sampleCurveFromPoints(pts, along) {
  if (!pts.length) return { x: 0, y: 0, ux: 1, uy: 0, along: 0 };
  if (along <= 0) return { ...pts[0] };
  if (along >= pts[pts.length - 1].along) return { ...pts[pts.length - 1] };
  let i1 = 1;
  while (i1 < pts.length - 1 && pts[i1].along < along) i1 += 1;
  const p0 = pts[i1 - 1];
  const p1 = pts[i1];
  const f = (along - p0.along) / ((p1.along - p0.along) || 1);
  const tangent = normalize({ x: lerp(p0.ux, p1.ux, f), y: lerp(p0.uy, p1.uy, f) });
  return {
    x: lerp(p0.x, p1.x, f),
    y: lerp(p0.y, p1.y, f),
    ux: tangent.x,
    uy: tangent.y,
    along
  };
}

function mapAlong(value, sourceStops, targetStops) {
  const source = clamp(value, sourceStops[0], sourceStops[sourceStops.length - 1]);
  for (let i = 1; i < sourceStops.length; i++) {
    if (source <= sourceStops[i]) {
      const t = (source - sourceStops[i - 1]) / ((sourceStops[i] - sourceStops[i - 1]) || 1);
      return lerp(targetStops[i - 1], targetStops[i], t);
    }
  }
  return targetStops[targetStops.length - 1];
}

function curveD(curve) {
  return curve.pts.map((point, index) => `${index ? "L" : "M"} ${fmt(point.x)} ${fmt(point.y)}`).join(" ");
}

function transformPathPairs(path, fn) {
  const values = numbers(path);
  const output = [];
  for (let i = 0; i < values.length; i += 2) {
    const point = fn({ x: values[i], y: values[i + 1] });
    output.push(point.x, point.y);
  }
  let index = 0;
  return path.replace(/-?\d*\.?\d+(?:e[-+]?\d+)?/gi, () => fmt(output[index++]));
}

function denseWarpPath(path, fn) {
  const dense = densePathPoints(path);
  if (!dense.length) return transformPathPairs(path, fn);
  const warped = dense.map(fn);
  return pathFromPoints(warped, true);
}

function denseWarpPathSmooth(path, fn, passes) {
  const dense = densePathPoints(path);
  if (!dense.length) return transformPathPairs(path, fn);
  let warped = dense.map(fn);
  if (passes > 0) warped = smoothClosed(warped, passes);
  return pathFromPoints(warped, true);
}

function densePathPoints(path) {
  const tokens = path.match(/[A-Za-z]|-?\d*\.?\d+(?:e[-+]?\d+)?/gi) || [];
  const points = [];
  let i = 0;
  let command = "";
  let current = null;
  let start = null;
  const isCommand = (token) => /^[A-Za-z]$/.test(token);
  const readNumber = () => Number(tokens[i++]);

  while (i < tokens.length) {
    if (isCommand(tokens[i])) command = tokens[i++];
    if (command === "M") {
      current = { x: readNumber(), y: readNumber() };
      start = { ...current };
      points.push({ ...current });
    } else if (command === "C") {
      while (i < tokens.length && !isCommand(tokens[i])) {
        const c1 = { x: readNumber(), y: readNumber() };
        const c2 = { x: readNumber(), y: readNumber() };
        const end = { x: readNumber(), y: readNumber() };
        addDenseCubic(points, current, c1, c2, end);
        current = end;
      }
    } else if (command === "L") {
      while (i < tokens.length && !isCommand(tokens[i])) {
        const end = { x: readNumber(), y: readNumber() };
        addDenseLine(points, current, end);
        current = end;
      }
    } else if (command === "Z" || command === "z") {
      if (start && current && Math.hypot(current.x - start.x, current.y - start.y) > .01) {
        points.push({ ...start });
      }
    } else {
      return [];
    }
  }
  if (points.length > 1) {
    const first = points[0];
    const last = points[points.length - 1];
    if (Math.hypot(first.x - last.x, first.y - last.y) < .01) points.pop();
  }
  return points;
}

function addDenseCubic(points, p0, p1, p2, p3) {
  if (!p0) return;
  const controlLen =
    Math.hypot(p1.x - p0.x, p1.y - p0.y) +
    Math.hypot(p2.x - p1.x, p2.y - p1.y) +
    Math.hypot(p3.x - p2.x, p3.y - p2.y);
  const steps = clamp(Math.ceil(controlLen / 2.4), 6, 38);
  for (let step = 1; step <= steps; step++) {
    points.push(cubicBezier(p0, p1, p2, p3, step / steps));
  }
}

function addDenseLine(points, p0, p1) {
  if (!p0) return;
  const len = Math.hypot(p1.x - p0.x, p1.y - p0.y);
  const steps = clamp(Math.ceil(len / 2.4), 1, 80);
  for (let step = 1; step <= steps; step++) {
    points.push({ x: p0.x + (p1.x - p0.x) * step / steps, y: p0.y + (p1.y - p0.y) * step / steps });
  }
}

function pathFromPoints(points, closed) {
  if (!points.length) return "";
  const body = points.map((point, index) => `${index ? "L" : "M"} ${fmt(point.x)} ${fmt(point.y)}`).join(" ");
  return closed ? `${body}Z` : body;
}

function numbers(value) {
  return (value.match(/-?\d*\.?\d+(?:e[-+]?\d+)?/gi) || []).map(Number);
}

function samplePath(path, count) {
  if (!path || !path.getTotalLength) return [];
  const length = path.getTotalLength();
  const points = [];
  for (let i = 0; i < count; i++) {
    const p = path.getPointAtLength((length * i) / count);
    points.push({ x: p.x, y: p.y });
  }
  return points;
}

function pointInPolygon(point, polygon) {
  let inside = false;
  for (let i = 0, j = polygon.length - 1; i < polygon.length; j = i++) {
    const a = polygon[i];
    const b = polygon[j];
    const hit = ((a.y > point.y) !== (b.y > point.y)) &&
      (point.x < (b.x - a.x) * (point.y - a.y) / ((b.y - a.y) || 1e-9) + a.x);
    if (hit) inside = !inside;
  }
  return inside;
}

function sideActive(side) {
  return state.side === "both" || state.side === side;
}

function smooth01(value) {
  const t = clamp(value, 0, 1);
  return t * t * (3 - 2 * t);
}

function clamp(value, min, max) {
  return Math.max(min, Math.min(max, value));
}

function lerp(a, b, t) {
  return a + (b - a) * t;
}

function normalize(v) {
  const len = Math.hypot(v.x, v.y) || 1;
  return { x: v.x / len, y: v.y / len };
}

function add(a, b) {
  return { x: a.x + b.x, y: a.y + b.y };
}

function sub(a, b) {
  return { x: a.x - b.x, y: a.y - b.y };
}

function scale(v, amount) {
  return { x: v.x * amount, y: v.y * amount };
}

function el(tag, attrs = {}) {
  const node = document.createElementNS(NS, tag);
  for (const [key, value] of Object.entries(attrs)) {
    if (value !== null && value !== undefined) node.setAttribute(key, String(value));
  }
  return node;
}

function fmt(value) {
  return String(parseFloat(Number(value).toFixed(3)));
}

function snapshot() {
  return {
    diagnostic: "hamster-thinking-loop-v1",
    source: "inlined:hamster-flat-layered-v18-noodle-hands.svg",
    stickerSource: "inlined:data-url-png-stickers",
    manualValueSource: "inlined:confirmed-defaults",
    headAnchorSource: "inlined:hamster-face-anchor-v1-settings.confirmed.json",
    state: { ...state },
    breathAmount: Number(breathAmount().toFixed(3)),
    blinkAmount: Number(blinkAmount().toFixed(3)),
    mouthMaskInsetEffective: Number(effectiveMouthMaskInset().toFixed(2)),
    browMicroEffective: {
      level: Number(effectiveBrowMicro().level.toFixed(2)),
      left: Number(effectiveBrowMicro().left.toFixed(2)),
      right: Number(effectiveBrowMicro().right.toFixed(2))
    },
    breathCurves: { ...THINKING_BREATH_CURVES },
    layering: [
      "original #hands-layer is hidden unless reference is enabled",
      "arm-back-split-layer draws the complete warped V18 hands behind #body-layer",
      "body-cast-shadow-on-hand-layer is clipped to the warped hands and inserted below #body-layer",
      "body-cast-shadow-on-hand-layer draws the body edge shadow onto the hands only",
      "body-belly-fill path is morphed for breathing",
      "thinking-head-pose-layer wraps ears/head/tufts/face for one rigid whole-head adjustment",
      "head look uses active SVG yaw/pitch deformation from the confirmed V15 anchor contract",
      "front head breathing is composed on top of look: body/head/face/ears/tufts/tie use separate thinking-specific breath curves that still close at 0% and 100%",
      "blink only compresses the bean eyes behind the sunglasses; sunglasses, lens highlights, bridge, face, and chin sticker remain untouched",
      "thinking-thought-dots-layer draws three horizontal mist-blue dots above the head; palette can switch to violet or sage, dots fade and float on a faster decoration cycle controlled by thoughtDotsCycle",
      "thinking eyebrows use confirmed path morph from thinking-brow-v1: left brow holds high/short, right brow holds low/inverted/short; browMicroArc only changes cubic control-point curvature through a closed-loop envelope, not endpoints or transforms",
      "mouth-left and mouth-right keep their original d and shorten from the outer ends via stroke-dasharray; linecap stays round and effective inset follows breath 5 -> 10 -> 5 by default",
      "thinking-head-pose-layer includes a tiny optional left-right head wobble controlled by headThinkWobble",
      "v2 blush contract: blushes are reparented into head-layer (rigid-bound to the white face); the clip path d is the same per-frame cheek in local coords with NO transform of its own, so head-layer carries the transform for both clip and content; the blush content only takes the cheek's pitch field warp, no affine blushPlaneTransform; this removes the content-affine vs clip-geometry desync that caused jitter and drift",
      "thinking-sticker-arm-layer draws the PNG cream arm patch above body and under head/face in formal mode; the extra SVG outer-shoulder bulge is off by default because the human-adjusted reference did not include it",
      "thinking-sticker-paw-layer draws the PNG orange paw patch above head/face in formal mode; the paw rotates around the PNG patch center with a tiny closed-loop wobble while the cream arm patch remains locked",
      "thinking-front-hand-layer is the old simplified SVG chin paw fallback and is hidden by default",
      "back hands receive a tiny passive translate plus a closed-loop rotation around the visible root; feet remain fixed",
      "tie knot shifts slightly and tie blade rotates around the knot center"
    ],
    markers: Object.fromEntries(Object.entries(markers).map(([side, data]) => [
      side,
      {
        hiddenShoulder: roundPoint(data.shoulder),
        visibleRoot: roundPoint(data.visibleRoot),
        elbow: roundPoint(data.elbow),
        wrist: roundPoint(data.wrist),
        tip: roundPoint(data.tip),
        sleeve: roundPoint(data.sleeve),
        sleeveAlong: Number(fmt(data.sleeveAlong)),
        autoContactSource: data.contactAuto.source
      }
    ])),
    status: "thinking loop confirmed export; 鹿鹿 confirmed on 2026-06-08"
  };
}

function roundPoint(point) {
  return { x: Number(fmt(point.x)), y: Number(fmt(point.y)) };
}

function escapeHtml(value) {
  return String(value)
    .replaceAll("&", "&amp;")
    .replaceAll("<", "&lt;")
    .replaceAll(">", "&gt;")
    .replaceAll('"', "&quot;");
}
